/* ---------------- auth ---------------- */
const W10 = 10 * 60 * 1000;
app.post('/api/login', (req, res) => {
  const { username, password } = req.body || {};
  const ipKey = 'login:' + req.ip, uKey = 'login:u:' + String(username || '').toLowerCase();
  // Throttle brute force on too many FAILED attempts (per-IP and per-username).
  if (rlOver(ipKey, 20, W10) || rlOver(uKey, 10, W10))
    return res.status(429).json({ error: 'Too many attempts. Please wait a few minutes and try again.' });
  const result = login(req, res, username || '', password || '');
  if (!result) { rlHit(ipKey, W10); rlHit(uKey, W10); return res.status(401).json({ error: 'Invalid username or password' }); }
  if (result.mfaRequired) return res.json({ mfaRequired: true, ticket: result.ticket });
  if (result.mfaEnroll) return res.json({ mfaEnroll: true, ticket: result.ticket, secret: result.secret });   // first-time setup at login
  res.json({ user: result });
});
// Pre-login QR for the enrollment-at-login flow (ticket-gated; no session yet).
app.get('/api/login/qr.svg', async (req, res) => {
  const otpauth = otpauthForTicket(String(req.query.ticket || ''));
  if (!otpauth) return res.status(404).send('expired');
  try { const svg = await QRCode.toString(otpauth, { type: 'svg', margin: 1, width: 220 }); res.set('Cache-Control', 'no-store').type('image/svg+xml').send(svg); }
  catch (e) { res.status(500).send('QR error'); }
});
app.post('/api/login/mfa', (req, res) => {
  // The 6-digit code is brute-forceable; cap FAILED attempts per ticket and per IP.
  const tKey = 'mfa:' + (req.body?.ticket || req.ip), ipKey = 'mfa:ip:' + req.ip;
  if (rlOver(tKey, 10, W10) || rlOver(ipKey, 30, W10))
    return res.status(429).json({ error: 'Too many attempts. Please wait a few minutes and try again.' });
  const user = completeMfa(req, res, req.body?.ticket || '', req.body?.code || '', !!req.body?.trust);
  if (!user) { rlHit(tKey, W10); rlHit(ipKey, W10); return res.status(401).json({ error: 'Invalid or expired code' }); }
  res.json({ user });
});
// Admin: turn required-MFA on/off (kill switch lives in env too).
app.get('/api/mfa/policy', requireAuth, requireAdmin, (req, res) => res.json({ required: mfaRequired() }));
app.post('/api/mfa/policy', requireAuth, requireAdmin, (req, res) => { setMfaRequired(!!req.body?.on); audit({ user: req.user, action: 'MFA_POLICY', detail: req.body?.on ? 'required' : 'optional', ip: req.ip }); res.json({ ok: true, required: mfaRequired() }); });
app.get('/api/mfa/setup', requireAuth, (req, res) => res.json(mfaSetup(req.user.id, req.user.username)));
// Scannable QR of the user's own otpauth URI — point Microsoft Authenticator at it
// instead of hand-typing the key. Authed: only the signed-in user gets their own.
app.get('/api/mfa/qr.svg', requireAuth, async (req, res) => {
  try {
    const { otpauth } = mfaSetup(req.user.id, req.user.username);
    const svg = await QRCode.toString(otpauth, { type: 'svg', margin: 1, width: 220 });
    res.set('Cache-Control', 'no-store').type('image/svg+xml').send(svg);
  } catch (e) { res.status(500).send('QR error'); }
});
app.post('/api/mfa/enable', requireAuth, (req, res) => {
  if (!mfaEnable(req.user.id, req.body?.code)) return res.status(400).json({ error: 'Code did not match — try again.' });
  audit({ user: req.user, action: 'MFA_ENABLE', ip: req.ip });
  res.json({ ok: true });
});
app.post('/api/mfa/disable', requireAuth, (req, res) => { mfaDisable(req.user.id); audit({ user: req.user, action: 'MFA_DISABLE', ip: req.ip }); res.json({ ok: true }); });

app.post('/api/logout', (req, res) => { logout(req, res); res.json({ ok: true }); });

// Outpatient (Akron House Recovery) is owner-only: the admin, plus any user ids the
// owner explicitly grants. Walled off from everyone else.
function outpatientAllowlist() { try { const a = JSON.parse(getState('outpatient_access') || '[]'); return Array.isArray(a) ? a : []; } catch { return []; } }
function canSeeOutpatient(user) { return !!user && (user.role === 'admin' || user.job_role === 'Director of Revenue Cycle Management' || outpatientAllowlist().includes(user.id)); }
function requireOutpatient(req, res, next) { if (!canSeeOutpatient(req.user)) return res.status(403).json({ error: 'Owner only.' }); next(); }
// One-time: everyone on the outpatient allowlist works the outpatient program,
// but the foundation access seed only gave them detox — so their facility chip
// couldn't reach Armada Clinical once the roster became facility-scoped.
// ONLY for users who already have access rows: a row-less user is "legacy
// unscoped" (sees everything) and granting their FIRST row would shrink them
// to one building — a regression, not a grant.
function grantOutpatientFacility(uid) {
  try {
    const opf = db.prepare(`SELECT id FROM org_facilities WHERE fkey='akron-house'`).get()?.id;
    if (!opf) return;
    const hasRows = db.prepare(`SELECT 1 FROM user_facility_access WHERE user_id=? LIMIT 1`).get(uid);
    if (!hasRows) return;
    db.prepare(`INSERT OR IGNORE INTO user_facility_access (user_id, facility_id, role) VALUES (?,?,(SELECT job_role FROM users WHERE id=?))`).run(uid, opf, uid);
  } catch { /* user may be gone */ }
}
try {
  if (getState('outpatient_access_backfill') !== 'done') {
    if (db.prepare(`SELECT id FROM org_facilities WHERE fkey='akron-house'`).get()?.id) {
      for (const uid of outpatientAllowlist()) grantOutpatientFacility(uid);
      setState('outpatient_access_backfill', 'done');
    }
  }
  // Repair for the first version of this backfill (already ran in production):
  // it granted row-less allowlisted users their FIRST row, silently shrinking
  // them from see-everything to one building. Undo exactly that shape: an
  // allowlisted user whose ONLY row is akron-house goes back to row-less.
  if (getState('outpatient_access_backfill') === 'done' && getState('outpatient_access_repair') !== 'done') {
    const opf = db.prepare(`SELECT id FROM org_facilities WHERE fkey='akron-house'`).get()?.id;
    if (opf) {
      for (const uid of outpatientAllowlist()) {
        const rows = db.prepare(`SELECT facility_id FROM user_facility_access WHERE user_id=?`).all(uid);
        if (rows.length === 1 && +rows[0].facility_id === +opf) {
          db.prepare(`DELETE FROM user_facility_access WHERE user_id=? AND facility_id=?`).run(uid, opf);
        }
      }
      setState('outpatient_access_repair', 'done');
    }
  }
} catch (e) { console.error('[outpatient access]', e.message); }

// ── Facilities registry (all 6 locations) for the consolidated ownership view ──
// Two Kipu connections: 'armada' (the existing login — Akron detox, Akron House,
// Dayton) and 'spark' (a separate login for Spark Recovery Indianapolis/Greenwood
// and Armada of Wheatfield, added when its credentials are provided). Each facility
// maps to a Kipu location name; the seed is editable by the owner.
const FACILITY_SEED = [
  { key: 'akron-detox', label: 'Armada Detox of Akron', brand: 'Armada', connection: 'armada', type: 'detox', locationName: '' },
  { key: 'akron-house', label: 'Armada Recovery of Akron', brand: 'Armada', connection: 'armada', type: 'outpatient', locationName: 'Akron House Recovery' },
  { key: 'dayton', label: 'Armada Recovery of Dayton', brand: 'Armada', connection: 'armada', type: 'outpatient', locationName: 'Dayton' },
  { key: 'indianapolis', label: 'Spark Recovery of Indianapolis', brand: 'Spark', connection: 'spark', type: 'outpatient', locationName: 'Indianapolis' },
  { key: 'greenwood', label: 'Spark Recovery of Greenwood', brand: 'Spark', connection: 'spark', type: 'outpatient', locationName: 'Greenwood' },
  { key: 'wheatfield', label: 'Armada Recovery of Wheatfield', brand: 'Spark', connection: 'spark', type: 'outpatient', locationName: 'Wheatfield' },
];
function getFacilities() {
  const s = getState('facilities_config');
  if (s) { try { const a = JSON.parse(s); if (Array.isArray(a) && a.length) return a; } catch { /* fall through */ } }
  return FACILITY_SEED;
}
// The Spark Kipu connection isn't wired yet — credentials come later. Until then its
// facilities show as "pending" in the ownership view rather than erroring.
function sparkConfigured() { return false; }
function connectionReachable(conn) { return conn === 'spark' ? sparkConfigured() : kipuConfigured(); }
// The 8 legal entities / locations that request orders. Derived from the HR roster
// (falls back to a fixed list). Used to tag order requests by where they came from.
const ORG_LOCATIONS_FALLBACK = ['Armada Detox of Akron', 'Akron House Recovery, LLC', 'Hilltop Recovery Home, LLC - AKRON', 'Armada Recovery Dayton, LLC', 'Hilltop Recovery Dayton, LLC', 'Spark Recovery, LLC', 'Reverie Sober Living of Indianapolis', 'Armada Recovery LLC ("Corporate")'];
const DETOX_LOCATION = 'Armada Detox of Akron';   // the default facility for new orders
function orgLocations() {
  try { const rows = db.prepare(`SELECT DISTINCT entity FROM hr_employees WHERE entity != '' ORDER BY entity`).all().map((r) => r.entity); if (rows.length) return rows; } catch { /* table may be empty */ }
  return ORG_LOCATIONS_FALLBACK;
}
// ── BHOS foundation: canonical facilities (org_facilities is the new spine) ──────
function orgFacilities() { return db.prepare(`SELECT * FROM org_facilities WHERE active=1 ORDER BY sort, id`).all(); }
// Resolve an entity-name spelling to its canonical facility (via entity_aliases).
function facilityForEntity(name) {
  const want = String(name || '').trim().toLowerCase();
  if (!want) return null;
  for (const f of orgFacilities()) {
    if (f.name.toLowerCase() === want) return f;
    try { for (const a of JSON.parse(f.entity_aliases || '[]')) if (String(a).toLowerCase() === want) return f; } catch { /* bad json */ }
  }
  return null;
}
// ── OPERATIONS CENTER: "what's happening right now" — one drillable board ──────
// Layer-5 architecture: Executive answers "right now"; Analytics answers "why".
// Every tile is a count + a drill target; tiles that can't compute are skipped.
function canSeeOps(user) { return !!user && (user.role === 'admin' || ['Executive Director', 'Director of Operations', 'Clinical Director', 'HR', 'Executive Assistant'].includes(user.job_role)); }
app.get('/api/opscenter', requireAuth, (req, res) => {
  if (!canSeeOps(req.user)) return res.status(403).json({ error: 'Leadership only.' });
  if (req.query.facility && !facilityAllowed(req.user, +req.query.facility)) return res.status(403).json({ error: 'No access to that facility.' });
  const today = appToday();
  const t = [];
  const add = (fn) => { try { const x = fn(); if (x) t.push(x); } catch { /* tile skipped */ } };
  const one = (sql, ...a) => db.prepare(sql).get(...a).n;
  // Optional facility filter: tiles whose tables carry facility_id scope to it;
  // the rest stay org-wide and say so — hiding work would be worse than mixing it.
  const fid = req.query.facility ? +req.query.facility : null;
  const fac = fid ? db.prepare(`SELECT * FROM org_facilities WHERE id = ?`).get(fid) : null;
  const F = fid ? ` AND facility_id=${fid}` : '';
  // RIGHT NOW — facility pulse
  add(() => ({ group: 'now', key: 'census', label: 'Census now', n: one(`SELECT COUNT(*) n FROM clients WHERE active=1 AND discharge_status IS NULL AND merged_into IS NULL${F}`), view: 'command' }));
  add(() => { const beds = one(`SELECT COUNT(*) n FROM beds WHERE 1=1${F}`); if (!beds) return null; const occ = one(`SELECT COUNT(*) n FROM beds WHERE status='Occupied'${F}`); return { group: 'now', key: 'beds', label: 'Beds available', n: beds - occ, sub: `${occ}/${beds} occupied`, view: 'bedboard' }; });
  add(() => ({ group: 'now', key: 'admits', label: 'Admissions today', n: one(`SELECT COUNT(DISTINCT COALESCE(kipu_id,name)) n FROM clients WHERE merged_into IS NULL AND substr(admit,1,10)=?${F}`, today), view: 'admitcheck' }));
  add(() => ({ group: 'now', key: 'arrivals', label: 'Expected arrivals', n: one(`SELECT COUNT(*) n FROM expected_arrivals WHERE scheduled_date=? AND status='expected'${F}`, today), view: 'arrivals' }));
  add(() => ({ group: 'now', key: 'penddc', label: 'Pending discharges', n: one(`SELECT COUNT(*) n FROM clients WHERE active=1 AND discharge_status IS NULL AND anticipated_dc IS NOT NULL AND substr(anticipated_dc,1,10) <= ?${F}`, addDays(today, 1)), view: 'dischargepage' }));
  add(() => { const n = one(`SELECT COUNT(*) n FROM incidents WHERE status='Open'${F}`); return { group: 'now', key: 'incidents', label: 'Open incidents', n, alert: n > 0, view: 'incidents' }; });
  // WORK QUEUES
  add(() => ({ group: 'queues', key: 'orders', label: 'Orders to place', n: fac ? one(`SELECT COUNT(*) n FROM order_requests WHERE status='requested' AND facility=?`, fac.name) : one(`SELECT COUNT(*) n FROM order_requests WHERE status='requested'`), view: 'corphub', tab: 'orders' }));
  add(() => ({ group: 'queues', key: 'maint', label: 'Maintenance open', n: one(`SELECT COUNT(*) n FROM maintenance_requests WHERE status IN ('open','in_progress')`), view: 'maintenance' }));
  add(() => ({ group: 'queues', key: 'concierge', label: 'Concierge open', n: one(`SELECT COUNT(*) n FROM requests WHERE status NOT IN ('done','closed','cancelled')`), view: 'concierge' }));
  add(() => ({ group: 'queues', key: 'obtasks', label: 'HR tasks due', n: one(`SELECT COUNT(*) n FROM hr_onboard_tasks WHERE done=0 AND due_date <= ?`, today), view: 'hcos', tab: 'people' }));
  add(() => ({ group: 'queues', key: 'corptasks', label: 'Projects in motion', n: one(`SELECT COUNT(*) n FROM corp_tasks WHERE status IN ('todo','doing','blocked')`), view: 'corphub', tab: 'projects' }));
  // Billing blockers — the fused Revenue OS lens: doc-gap discharges + expired
  // auths + patients in care beyond their approved days. Drill lands where the
  // most actionable blocker lives.
  add(() => {
    const gaps = one(`SELECT COUNT(*) n FROM clients WHERE discharge_doc_gap=1 AND substr(discharge_date,1,10) >= date(?, '-6 day')${F}`, today);
    const expAuth = one(`SELECT COUNT(*) n FROM authorizations WHERE status IN ('active','renewed') AND end_date IS NOT NULL AND end_date < ?${fid ? ` AND facility_id=${fid}` : ''}`, today);
    let over = 0;
    try { over = one(`SELECT COUNT(*) n FROM authorizations a JOIN clients c ON c.id=a.client_id WHERE a.status IN ('active','renewed') AND a.approved_days IS NOT NULL AND c.active=1 AND (a.end_date IS NULL OR a.end_date >= ?) AND julianday(?) - julianday(substr(c.admit,1,10)) > a.approved_days${fid ? ` AND c.facility_id=${fid}` : ''}`, today, today); } catch { /* optional */ }
    const parts = [gaps ? `${gaps} doc-gap` : null, expAuth ? `${expAuth} expired auth` : null, over ? `${over} beyond auth` : null].filter(Boolean);
    return { group: 'queues', key: 'billing', label: 'Billing blockers', n: gaps + expAuth + over, alert: (expAuth + over) > 0, sub: parts.join(' · ') || undefined, view: (expAuth || over) ? 'authreg' : 'retention' };
  });
  add(() => {
    const nowMin = new Date(new Date().toLocaleString('en-US', { timeZone: APP_TZ })).toISOString().slice(0, 16).replace('T', ' ');
    const CARE_SQL = `(department LIKE '%case%' OR department LIKE '%therap%' OR department LIKE '%clinic%' OR department LIKE '%counsel%' OR department LIKE '%peer%')`;
    const broken = one(`SELECT COUNT(*) n FROM requests WHERE status != 'Done' AND promise_at IS NOT NULL AND promise_at < ?`, nowMin);
    const waiting = one(`SELECT COUNT(*) n FROM requests WHERE status != 'Done' AND ${CARE_SQL}`);
    return { group: 'now', key: 'promises', label: 'Service promises at risk', n: broken, alert: broken > 0, sub: waiting ? waiting + ' meeting request' + (waiting === 1 ? '' : 's') + ' waiting' : undefined, view: 'appts' };
  });
  add(() => {
    const ran = db.prepare(`SELECT COUNT(*) n FROM billing_ready_status WHERE date=?${F}`).get(today).n;
    if (!ran) return { group: 'queues', key: 'encounters', label: 'Encounters check', n: 0, sub: 'not run yet today', view: 'billingready' };
    const miss = one(`SELECT COUNT(*) n FROM billing_ready_status WHERE date=? AND status IN ('missing','sync_error')${F}`, today);
    return { group: 'queues', key: 'encounters', label: 'Encounters missing today', n: miss, alert: miss > 0, sub: 'billable-day watch', view: 'billingready' };
  });
  add(() => { const n = one(`SELECT COUNT(*) n FROM authorizations WHERE status IN ('active','renewed') AND end_date IS NOT NULL AND end_date <= ?${fid ? ` AND facility_id=${fid}` : ''}`, addDays(today, 7)); const exp = one(`SELECT COUNT(*) n FROM authorizations WHERE status IN ('active','renewed') AND end_date IS NOT NULL AND end_date < ?${fid ? ` AND facility_id=${fid}` : ''}`, today); return { group: 'queues', key: 'auths', label: 'Auth renewals ≤7d', n, alert: exp > 0, sub: exp ? `${exp} already expired` : undefined, view: 'authreg' }; });
  // PEOPLE & COMPLIANCE
  add(() => { const n = one(`SELECT COUNT(*) n FROM hr_reviews WHERE status='open' AND due_date < ?`, today); return { group: 'people', key: 'reviews', label: 'Reviews overdue', n, alert: n > 0, view: 'hcos', tab: 'reviews' }; });
  add(() => { const n = one(`SELECT COUNT(*) n FROM hr_certifications c JOIN hr_employees e ON e.id=c.employee_id AND e.status='active' WHERE c.expires IS NOT NULL AND c.expires <= ?`, addDays(today, 30)); return { group: 'people', key: 'certs', label: 'Certs expiring ≤30d', n, alert: n > 0, view: 'hcos', tab: 'certs' }; });
  add(() => ({ group: 'people', key: 'leave', label: 'Leave requests', n: one(`SELECT COUNT(*) n FROM hr_leave WHERE status='requested'`), view: 'hcos', tab: 'leave' }));
  add(() => { const n = one(`SELECT COUNT(*) n FROM hr_cases WHERE status='open'`); return { group: 'people', key: 'cases', label: 'Open HR cases', n, view: 'hcos', tab: 'relations' }; });
  add(() => ({ group: 'people', key: 'pipeline', label: 'Hiring pipeline', n: one(`SELECT COUNT(*) n FROM candidates WHERE stage NOT IN ('Hired','Passed')`), view: 'hiring' }));
  add(() => { const n = one(`SELECT COUNT(*) n FROM insurance_policies WHERE status IN ('active','pending') AND expiration_date IS NOT NULL AND expiration_date <= ?`, addDays(today, 60)); return { group: 'people', key: 'ins', label: 'Insurance renewing ≤60d', n, alert: n > 0, view: 'corphub', tab: 'insurance' }; });
  // Activity feed: the last business moments off the org_events spine.
  let events = [];
  try { events = db.prepare(`SELECT event, summary, actor, at FROM org_events ORDER BY id DESC LIMIT 20`).all(); } catch { /* feed optional */ }
  res.json({ today, tiles: t, events });
});

// ── TODAY: the personal task inbox — everything waiting on ME, due-ordered ─────
app.get('/api/today', requireAuth, (req, res) => {
  const today = appToday();
  const items = [];
  const add = (fn) => { try { fn(); } catch { /* source skipped */ } };
  const me = req.user;
  // My project/errand tasks on the corporate board (matched by assignee name).
  add(() => {
    if (!canSeeCorp(me)) return;
    for (const t of db.prepare(`SELECT id, title, category, priority, due_date, status FROM corp_tasks WHERE status IN ('todo','doing','blocked') AND (assignee IS NULL OR assignee='' OR assignee LIKE ?) ORDER BY (due_date IS NULL), due_date LIMIT 12`).all('%' + (me.name || '') + '%')) {
      items.push({ label: t.title, sub: `${t.category}${t.due_date ? ' · due ' + t.due_date : ''}`, overdue: !!(t.due_date && t.due_date < today), view: 'corphub', tab: 'projects' });
    }
  });
  // Tasks assigned to me by a teammate (followups).
  add(() => {
    for (const f of db.prepare(`SELECT id, text, due_date FROM followups WHERE done=0 AND assignee_id=? ORDER BY (due_date IS NULL), due_date LIMIT 10`).all(me.id)) {
      items.push({ label: f.text, sub: f.due_date ? 'due ' + f.due_date : 'assigned to you', overdue: !!(f.due_date && f.due_date < today), view: 'mytasks' });
    }
  });
  // My Desk: the owner's own due/overdue items…
  add(() => {
    if (me.role !== 'admin') return;
    for (const d of db.prepare(`SELECT id, title, due_date, due_time, with_who FROM desk_items WHERE owner_id=? AND status != 'done' AND due_date IS NOT NULL AND due_date <= ? AND (snooze_until IS NULL OR snooze_until <= ?) ORDER BY due_date, due_time LIMIT 10`).all(me.id, today, today)) {
      items.push({ label: d.title, sub: `My Desk${d.due_time ? ' · ' + d.due_time : ''}${d.with_who ? ' · w/ ' + d.with_who : ''}`, overdue: d.due_date < today, view: 'mydesk' });
    }
  });
  // …and for everyone else: what the owner is waiting on YOU for.
  add(() => {
    for (const d of db.prepare(`SELECT d.title, d.due_date, u.name AS owner_name FROM desk_items d JOIN users u ON u.id=d.owner_id WHERE d.with_user_id=? AND d.status='waiting' ORDER BY d.id DESC LIMIT 5`).all(me.id)) {
      items.push({ label: `${d.owner_name} is waiting on: ${d.title}`, sub: d.due_date ? 'by ' + d.due_date : 'when you can', overdue: !!(d.due_date && d.due_date < today), view: 'mytasks' });
    }
  });
  // Leadership: anything burning on the Ops Center lands in Today too.
  add(() => {
    if (!canSeeOps(me)) return;
    const one = (sql, ...a) => db.prepare(sql).get(...a).n;
    const inc = one(`SELECT COUNT(*) n FROM incidents WHERE status='Open'`);
    if (inc) items.push({ label: `${inc} open incident${inc === 1 ? '' : 's'} to review`, sub: 'Ops Center', overdue: true, view: 'incidents' });
    if (canSeeHR(me)) { const rev = one(`SELECT COUNT(*) n FROM hr_reviews WHERE status='open' AND due_date < ?`, today); if (rev) items.push({ label: `${rev} review${rev === 1 ? '' : 's'} overdue`, sub: 'People OS', overdue: true, view: 'hcos', tab: 'reviews' }); }
    if (canSeeCorp(me)) { const ord = one(`SELECT COUNT(*) n FROM order_requests WHERE status='requested' AND priority IN ('High','Urgent')`); if (ord) items.push({ label: `${ord} high-priority order${ord === 1 ? '' : 's'} to place`, sub: 'Corporate Hub', overdue: false, view: 'corphub', tab: 'orders' }); }
  });
  // Excellence OS: culture becomes visible — recognition finds the person it names.
  add(() => {
    const first = (me.name || '').split(/\s+/)[0] || '';
    if (!first) return;
    for (const r of db.prepare(`SELECT principle, story, by_name FROM extra_mile WHERE created_at >= datetime('now','-7 day') AND (lower(trim(person)) = lower(?) OR lower(trim(person)) = lower(?)) ORDER BY id DESC LIMIT 3`).all(me.name || '', first)) {
      items.push({ label: `🌟 You were recognized${r.principle ? ' — ' + r.principle : ''}`, sub: `${r.story.slice(0, 90)}${r.by_name ? ' — ' + r.by_name : ''}`, overdue: false, view: 'team' });
    }
  });
  // Coaching follow-ups I promised — a coaching note isn't done until the circle-back.
  add(() => {
    for (const c of db.prepare(`SELECT h.id, h.follow_up, h.standard, e.first_name, e.last_name FROM hr_coaching h JOIN hr_employees e ON e.id=h.employee_id WHERE h.by_name=? AND h.follow_up IS NOT NULL AND h.follow_up <= ? AND h.followed_up_at IS NULL ORDER BY h.follow_up LIMIT 5`).all(me.name || '', today)) {
      items.push({ label: `Coaching follow-up: ${c.first_name} ${c.last_name}`, sub: c.standard ? c.standard.slice(0, 80) : 'circle back on the coaching note', overdue: c.follow_up < today, view: 'hcos' });
    }
  });
  // Friday: four questions, two minutes — the week closes with a reflection.
  add(() => {
    const dow = new Date(today + 'T12:00:00').getDay();
    if (dow !== 5 && dow !== 6 && dow !== 0) return;
    if (db.prepare(`SELECT 1 FROM weekly_reflections WHERE user_id=? AND week=?`).get(me.id, excWeek(today))) return;
    items.push({ label: '🪞 Weekly reflection — four questions, two minutes', sub: 'What made you proud? Who lived the standards?', overdue: false, view: 'team' });
  });
  // Monthly Excellence Survey — six questions, anonymous; stands until answered.
  add(() => {
    if (db.prepare(`SELECT 1 FROM excellence_survey_done WHERE user_id=? AND month=?`).get(me.id, today.slice(0, 7))) return;
    items.push({ label: '📊 Monthly excellence survey — six questions, anonymous', sub: 'Team page · your answers are stored without your name', overdue: false, view: 'team' });
  });
  items.sort((a, b) => (b.overdue ? 1 : 0) - (a.overdue ? 1 : 0));
  res.json({ today, items: items.slice(0, 15) });
});

// ── GLOBAL SEARCH: people, work, vendors — walls respected per source ──────────
app.get('/api/search', requireAuth, (req, res) => {
  const q = String(req.query.q || '').trim();
  if (q.length < 2) return res.json({ results: [] });
  const like = '%' + q + '%';
  const me = req.user;
  const out = [];
  const add = (fn) => { try { fn(); } catch { /* source skipped */ } };
  const eaWalled = me.job_role === 'Executive Assistant' && me.role !== 'admin';   // corporate lane: no clinical
  add(() => {
    if (eaWalled) return;
    const sFc = facCtx(req);
    if (sFc.deny) return;
    for (const c of db.prepare(`SELECT id, name, pref, room, active FROM clients WHERE merged_into IS NULL AND (name LIKE ? OR pref LIKE ?)${sFc.frag('facility_id')} ORDER BY active DESC, id DESC LIMIT 6`).all(like, like)) {
      out.push({ type: 'client', icon: '🛏', id: c.id, label: c.name || c.pref, sub: (c.active ? 'In care' : 'Discharged') + (c.room ? ' · Room ' + c.room : '') });
    }
  });
  add(() => {
    if (!canSeeHR(me)) return;
    for (const e of db.prepare(`SELECT id, first_name, last_name, job_title, entity, status FROM hr_employees WHERE (first_name || ' ' || last_name) LIKE ? ORDER BY (status!='active'), last_name LIMIT 6`).all(like)) {
      out.push({ type: 'employee', icon: '👤', id: e.id, label: `${e.first_name} ${e.last_name}`, sub: [e.job_title, e.entity].filter(Boolean).join(' · ') || (e.status === 'active' ? 'Active' : 'Inactive') });
    }
  });
  add(() => {
    if (!canSeeCorp(me)) return;
    for (const o of db.prepare(`SELECT id, item_name, facility, status FROM order_requests WHERE item_name LIKE ? AND status IN ('requested','ordered') ORDER BY id DESC LIMIT 5`).all(like)) {
      out.push({ type: 'order', icon: '🛒', id: o.id, label: o.item_name, sub: `${o.status} · ${o.facility}` });
    }
    for (const v of db.prepare(`SELECT id, name, category FROM vendors WHERE name LIKE ? LIMIT 4`).all(like)) {
      out.push({ type: 'vendor', icon: '📇', id: v.id, label: v.name, sub: v.category || 'Vendor' });
    }
  });
  res.json({ results: out.slice(0, 18) });
});

// ── PERMISSION MATRIX (Phase 2 lever): rows here GRANT module access live ──────
const PERM_MODULES = ['corporate', 'facility_ops', 'admissions', 'census', 'clinical', 'casemgmt', 'peer', 'ur', 'billing', 'hr', 'finance', 'bd', 'compliance', 'scheduling', 'documents', 'tasks', 'reports', 'admin'];
