// Kiosk queue board: the client's own requests with position, honest wait, promise,
// and the READY flash. Preferred-name only (weakly-authenticated device).
app.get('/api/kiosk/queue', requireKiosk, (req, res) => {
  const cid = +req.query.client_id;
  if (!cid) return res.json({ requests: [] });
  const kfid = req.kioskFacilityId || defaultFacilityId();
  const kc = db.prepare(`SELECT facility_id FROM clients WHERE id = ?`).get(cid);
  if (kc && kc.facility_id != null && kfid && kc.facility_id !== kfid) return res.json({ requests: [] });
  const open = db.prepare(`SELECT id, department, text, status, created_at, promise_at, ready_at, claimed_by FROM requests WHERE client_id=? AND status != 'Done' ORDER BY id`).all(cid);
  const allOpen = db.prepare(`SELECT id FROM requests WHERE status != 'Done'${kfid ? ` AND (facility_id = ${kfid} OR facility_id IS NULL)` : ''} ORDER BY id`).all().map((x) => x.id);
  res.json({
    estWaitMin: estWaitMinutes(),
    requests: open.map((r) => ({
      id: r.id, text: r.text.slice(0, 80), status: r.ready_at ? 'ready' : (r.status === 'In progress' ? 'helping' : 'waiting'),
      position: allOpen.indexOf(r.id) + 1, waitMin: Math.max(0, Math.round((Date.now() - Date.parse(r.created_at + 'Z')) / 60000)),
      promise: r.promise_at ? ('by ' + r.promise_at.slice(11, 16)) : null, with: r.claimed_by || null,
    })),
  });
});

/* ═══ MY DESK — the owner's one capture inbox (tasks · follow-ups · ideas ·
   appointments). Capture from the app, a text, or Siri; dates parse out of the
   sentence; waiting-on items nudge people through their Today inbox; a morning
   digest email does the remembering. Admin-only. ═══ */
function parseWhen(text, today) {
  let t = ' ' + String(text || '') + ' ';
  let date = null, time = null;
  const timeM = t.match(/\b(?:at )?(\d{1,2})(?::(\d{2}))?\s*(am|pm)\b/i);
  if (timeM) { let h = +timeM[1] % 12; if (/pm/i.test(timeM[3])) h += 12; time = String(h).padStart(2, '0') + ':' + (timeM[2] || '00'); t = t.replace(timeM[0], ' '); }
  if (/\btoday\b/i.test(t)) { date = today; t = t.replace(/\btoday\b/i, ' '); }
  else if (/\btomorrow\b/i.test(t)) { date = addDays(today, 1); t = t.replace(/\btomorrow\b/i, ' '); }
  else if (/\bnext week\b/i.test(t)) { date = addDays(today, 7); t = t.replace(/\bnext week\b/i, ' '); }
  else {
    const dows = ['sunday', 'monday', 'tuesday', 'wednesday', 'thursday', 'friday', 'saturday'];
    for (let i = 0; i < 7; i++) {
      const re = new RegExp('\\b(?:on |next )?' + dows[i] + '\\b', 'i');
      if (re.test(t)) { const diff = ((i - dowOf(today)) + 7) % 7 || 7; date = addDays(today, diff); t = t.replace(re, ' '); break; }
    }
  }
  const md = t.match(/\b(\d{1,2})\/(\d{1,2})(?:\/(\d{2,4}))?\b/);
  if (!date && md) {
    const y = md[3] ? (md[3].length === 2 ? '20' + md[3] : md[3]) : today.slice(0, 4);
    date = `${y}-${String(md[1]).padStart(2, '0')}-${String(md[2]).padStart(2, '0')}`;
    if (!md[3] && date < today) date = String(+y + 1) + date.slice(4);
    t = t.replace(md[0], ' ');
  }
  if (time && !date) date = today;
  const clean = t.replace(/\s+/g, ' ').trim().replace(/^(remind me to |remind me |remember to |remember |todo:? |task:? )/i, '');
  return { clean: clean || String(text || '').trim(), date, time };
}
function deskMatchUser(name) {
  if (!String(name || '').trim()) return null;
  return db.prepare(`SELECT id, name, username FROM users WHERE active=1 AND lower(name) LIKE ? ORDER BY id LIMIT 1`).get('%' + String(name).toLowerCase().trim() + '%') || null;
}
function deskCapture(ownerId, rawText, source) {
  const today = appToday();
  const { clean, date, time } = parseWhen(rawText, today);
  // "… with Josh" / "@Josh" → the person who has to help close it
  let withWho = null, title = clean;
  const wm = clean.match(/(?:\bwith |\bw\/ ?|@)([A-Z][a-zA-Z]+(?: [A-Z][a-zA-Z]+)?)/);
  if (wm) withWho = wm[1];
  const kind = /\bidea\b/i.test(clean) ? 'idea' : (time ? 'appt' : withWho ? 'followup' : 'task');
  const u = withWho ? deskMatchUser(withWho) : null;
  const info = db.prepare(`INSERT INTO desk_items (owner_id, title, kind, with_who, with_user_id, due_date, due_time, source, status) VALUES (?,?,?,?,?,?,?,?, ?)`)
    .run(ownerId, String(title).slice(0, 300), kind, withWho, u ? u.id : null, date, time, source, withWho ? 'waiting' : 'open');
  deskClassifyAsync(info.lastInsertRowid, title);
  return { id: info.lastInsertRowid, title, date, time, withWho, matched: u ? u.name : null, kind };
}
function deskBuckets() {
  try { const a = JSON.parse(getState('desk_buckets') || 'null'); if (Array.isArray(a) && a.length) return a; } catch { /* defaults */ }
  return ['Clinical', 'Medical', 'Maintenance', 'Expansion', 'Corporate', 'HR / People', 'Finance', 'Marketing', 'IT / App', 'Personal'];
}
// Filing happens AFTER the save, never before — capture speed is sacred. The AI
// picks strictly from the bucket list + facility registry; unclear stays unfiled.
function deskClassifyAsync(id, title) {
  if (!claudeConfigured()) return;
  const facs = orgFacilities().filter((f) => f.type !== 'corporate' && f.active).map((f) => f.name);
  classifyDeskItem(title, deskBuckets(), facs, JOB_ROLES).then((r) => {
    const bucket = deskBuckets().find((b) => b.toLowerCase() === String(r.bucket || '').toLowerCase()) || null;
    const fac = r.facility ? facilityForEntity(r.facility) : null;
    const role = JOB_ROLES.find((x) => x.toLowerCase() === String(r.role || '').toLowerCase()) || null;
    if (bucket || fac || role) db.prepare(`UPDATE desk_items SET bucket=COALESCE(?, bucket), facility_id=COALESCE(?, facility_id), suggested_role=COALESCE(?, suggested_role) WHERE id=?`).run(bucket, fac ? fac.id : null, role, id);
  }).catch((e) => console.error('[desk] classify #' + id + ':', e.message));   // loud, never silent
}
function noteToken() { let t = getState('desk_note_token'); if (!t) { t = crypto.randomBytes(14).toString('base64url'); setState('desk_note_token', t); } return t; }
app.get('/api/desk', requireAuth, requireAdmin, (req, res) => {
  const today = appToday();
  const items = db.prepare(`SELECT d.*, u.name AS matched_name, f.name AS facility_name FROM desk_items d LEFT JOIN users u ON u.id=d.with_user_id LEFT JOIN org_facilities f ON f.id=d.facility_id WHERE d.owner_id=? AND (d.status != 'done' OR d.done_at >= datetime('now','-14 day')) ORDER BY d.status='done', (d.due_date IS NULL), d.due_date, d.due_time, d.id DESC`).all(req.user.id)
    .map((d) => ({ ...d, overdue: !!(d.due_date && d.due_date < today && d.status !== 'done'), snoozed: !!(d.snooze_until && d.snooze_until > today) }));
  // Backfill: anything still unfiled gets classified now (a few per page-load —
  // this is what catches items captured before filing existed, or after edits).
  for (const it of items.filter((x) => x.status !== 'done' && !x.bucket && !x.suggested_role).slice(0, 8)) deskClassifyAsync(it.id, it.title);
  // Staff by role, so a suggested role becomes an assigned NAME in two taps.
  const staffByRole = {};
  for (const u of db.prepare(`SELECT name, job_role FROM users WHERE active=1 AND job_role IS NOT NULL ORDER BY name`).all()) {
    (staffByRole[u.job_role] = staffByRole[u.job_role] || []).push(u.name);
  }
  const base = (getState('public_base_url') || process.env.PUBLIC_BASE_URL || appBaseUrl(req)).replace(/\/$/, '');
  res.json({
    today, items, staffByRole,
    buckets: deskBuckets(),
    facilities: orgFacilities().filter((f) => f.type !== 'corporate' && f.active).map((f) => ({ id: f.id, name: f.name })),
    settings: { digestHour: +(getState('desk_digest_hour') || 7), email: getState('desk_email') || '', noteUrl: `${base}/api/inbound/note?t=${noteToken()}` },
  });
});
