// Guard for ?facility= params: the requested facility must be one the caller can
// see (admin/ED see all). Closes the read-any-facility hole the audit flagged.
// Facility scope for READS (Rebuild Phase 2). ?facility=<id> (validated) scopes
// to one facility; no param = everything the caller may see (admin/ED: all).
// fc.deny → the caller asked for a facility they can't see (endpoint 403s,
// never silently empties — fail-visible). fc.frag(col) → safe SQL fragment.
function facCtx(req) {
  const q = req.query.facility;
  if (q !== undefined && q !== '') {
    const fid = +q;
    // Must be a real positive integer id (blocks NaN, floats, Infinity from ?facility=1e999).
    if (!Number.isInteger(fid) || fid <= 0 || !facilityAllowed(req.user, fid)) return { one: null, deny: true, frag: () => ' AND 1=0' };
    return { one: fid, deny: false, frag: (col) => ` AND ${col} = ${fid}` };   // explicit pick: strict
  }
  if (req.user.role === 'admin' || ['Executive Director', 'Executive Assistant'].includes(req.user.job_role)) return { one: null, deny: false, frag: () => '' };
  const ids = db.prepare(`SELECT facility_id FROM user_facility_access WHERE user_id=?`).all(req.user.id).map((r) => +r.facility_id).filter(Boolean);
  if (!ids.length) return { one: null, deny: false, frag: () => '' };   // legacy user with no access rows — unscoped, as today
  // "All my facilities" (no explicit pick): NULL-tolerant so an unstamped row is
  // fail-VISIBLE (surfaces to the operator) instead of silently vanishing.
  return { one: ids.length === 1 ? ids[0] : null, deny: false, frag: (col) => ` AND (${col} IS NULL OR ${col} IN (${ids.join(',')}))` };
}
const denyFac = (fc, res) => { if (fc.deny) { res.status(403).json({ error: 'No access to that facility.' }); return true; } return false; };
function facilityAllowed(user, fid) {
  if (!fid) return true;   // "all my facilities" — resolved per-user elsewhere
  // Must match /api/me's org-wide set — the chip and enforcement must agree.
  if (user.role === 'admin' || ['Executive Director', 'Executive Assistant'].includes(user.job_role)) return true;
  // A user with NO access rows is legacy/unscoped (sees everything, as pre-Phase-2) —
  // never lock them out. Once they HAVE rows, only those facilities are allowed.
  const rows = db.prepare(`SELECT 1 FROM user_facility_access WHERE user_id=? LIMIT 1`).get(user.id);
  if (!rows) return true;
  return !!db.prepare(`SELECT 1 FROM user_facility_access WHERE user_id=? AND facility_id=?`).get(user.id, +fid);
}
// Resolve the facility to STAMP on a write, and refuse a facility the caller can't
// see (closes the write-side IDOR the read guard already closes). Returns a number,
// or null with res already 403'd.
function stampFac(req, res, bodyFid) {
  const asked = (bodyFid != null && bodyFid !== '' && +bodyFid) || (req.query.facility ? +req.query.facility : 0);
  if (asked) {
    if (!Number.isInteger(asked) || asked <= 0 || !facilityAllowed(req.user, asked)) { res.status(403).json({ error: 'No access to that facility.' }); return null; }
    return asked;
  }
  return facCtx(req).one || defaultFacilityId();
}
// Per-client endpoints: verify the CLIENT belongs to a facility the caller may
// see (and matches the chip's explicit pick). Returns the client row, or null
// with a 404 already sent — a cross-facility id must be indistinguishable from
// a nonexistent one.
function clientFacGuard(req, res, clientId, cols = '*') {
  const c = db.prepare(`SELECT ${cols}${cols === '*' ? '' : ', facility_id'} FROM clients WHERE id = ?`).get(clientId);
  if (!c) { res.status(404).json({ error: 'Not found' }); return null; }
  const fc = facCtx(req);
  if (fc.deny || (fc.one && c.facility_id != null && c.facility_id !== fc.one) || (c.facility_id != null && !facilityAllowed(req.user, c.facility_id))) {
    res.status(404).json({ error: 'Not found' }); return null;
  }
  return c;
}

// Insurance: the coverage lines we track, and which are REQUIRED so the matrix can
// flag any entity that's missing one (configurable by the owner).
const COVERAGE_TYPES = ['General Liability', 'Professional Liability', 'Property', 'Workers Compensation', 'Commercial Auto', 'Umbrella / Excess', 'Cyber Liability', 'Directors & Officers', 'Employment Practices (EPLI)', 'Abuse & Molestation'];
function requiredCoverage() {
  try { const a = JSON.parse(getState('insurance_required') || 'null'); if (Array.isArray(a) && a.length) return a; } catch { /* default below */ }
  return ['General Liability', 'Professional Liability', 'Property', 'Workers Compensation', 'Abuse & Molestation'];
}
function insuranceRecipients() {
  const set = (getState('insurance_email') || '').trim();
  if (set) return set;
  return [...new Set(['chavaa@armadarecovery.com', (getState('census_email_to') || process.env.CENSUS_EMAIL_TO || '').trim()].filter(Boolean))].join(',');
}
// Status of a policy relative to today: cancelled/pending pass through; otherwise
// expired (past), expiring (≤60d), or active.
function policyStatus(p, today) {
  if (p.status === 'cancelled' || p.status === 'pending') return p.status;
  const exp = (p.expiration_date || '').slice(0, 10);
  if (!exp) return p.status || 'active';
  const days = Math.round((Date.parse(exp + 'T00:00:00') - Date.parse(today + 'T00:00:00')) / 864e5);
  if (days < 0) return 'expired';
  if (days <= 60) return 'expiring';
  return 'active';
}
function daysToExpiry(exp, today) { if (!exp) return null; return Math.round((Date.parse(String(exp).slice(0, 10) + 'T00:00:00') - Date.parse(today + 'T00:00:00')) / 864e5); }
app.get('/api/me', (req, res) => {
  const user = currentUser(req);
  if (user) {
    user.outpatientAccess = canSeeOutpatient(user); user.corpAccess = canSeeCorp(user); user.hrAccess = canSeeHR(user); user.opsAccess = canSeeOps(user); user.authAccess = canSeeAuth(user); user.billingAccess = canSeeBilling(user); user.apptsAccess = canSeeAppts(user);
    // Facility scope for the shell chip. Org-wide roles are resolved DYNAMICALLY
    // (never from stored rows) so a facility added after their access rows were
    // seeded still shows up — facilityAllowed() already lets them in everywhere,
    // and the chip must agree with enforcement. Everyone else: explicit
    // user_facility_access rows win, with a detox fallback for legacy users.
    try {
      const orgWide = user.role === 'admin' || ['Executive Director', 'Executive Assistant'].includes(user.job_role || '');
      let facs;
      if (orgWide) {
        // Org-wide users also get Corporate in the switcher — it's a real "place"
        // with its own toolset, not a hidden mode (facility-first navigation).
        facs = db.prepare(`SELECT id, fkey, name, type, modules FROM org_facilities WHERE active = 1 ORDER BY (type='corporate'), sort, id`).all();
      } else {
        facs = db.prepare(`SELECT f.id, f.fkey, f.name, f.type, f.modules FROM user_facility_access ua JOIN org_facilities f ON f.id = ua.facility_id WHERE ua.user_id = ? AND f.active = 1 ORDER BY f.sort, f.id`).all(user.id);
        if (!facs.length) facs = db.prepare(`SELECT id, fkey, name, type, modules FROM org_facilities WHERE active = 1 AND type != 'corporate' ORDER BY sort, id LIMIT 1`).all();
      }
      // Each chip entry carries its TYPE and resolved MODULE SET — the sidebar
      // rebuilds itself from this when the user switches facilities.
      user.facilities = facs.map((f) => ({ id: f.id, fkey: f.fkey, name: f.name, type: f.type || 'outpatient', modules: facilityModules(f) }));
    } catch { user.facilities = []; }
  }
  res.json({ user: user || null });
});

