/* ---------------- Shift checklist (recurring walk-around duties) ---------------- */
app.get('/api/shift-checklist', requireAuth, (req, res) => {
  const today = appToday(), sh = currentShift();
  const tasks = db.prepare(`SELECT id, label FROM shift_tasks WHERE active = 1 ORDER BY sort, id`).all();
  const done = {}; db.prepare(`SELECT task_id, by_name FROM shift_task_done WHERE shift_date = ? AND shift = ?`).all(today, sh).forEach((r) => { done[r.task_id] = r.by_name || ''; });
  const items = tasks.map((t) => ({ id: t.id, label: t.label, done: t.id in done, by: done[t.id] || '' }));
  const d = items.filter((i) => i.done).length;
  res.json({ shift: sh, items, done: d, total: items.length, pct: items.length ? Math.round(d / items.length * 100) : 100, canEdit: req.user.role === 'admin' || ['Director of Operations', 'Clinical Director', 'Executive Director'].includes(req.user.job_role || '') });
});
app.post('/api/shift-checklist/:id', requireAuth, (req, res) => {
  const today = appToday(), sh = currentShift(), id = +req.params.id;
  if (req.body && req.body.done === false) db.prepare(`DELETE FROM shift_task_done WHERE task_id = ? AND shift_date = ? AND shift = ?`).run(id, today, sh);
  else db.prepare(`INSERT OR IGNORE INTO shift_task_done (task_id, shift_date, shift, by_id, by_name) VALUES (?,?,?,?,?)`).run(id, today, sh, req.user.id, req.user.name);
  res.json({ ok: true });
});
app.post('/api/shift-checklist/template/edit', requireAuth, (req, res) => {
  if (!(req.user.role === 'admin' || ['Director of Operations', 'Clinical Director', 'Executive Director'].includes(req.user.job_role || ''))) return res.status(403).json({ error: 'Leadership only.' });
  const b = req.body || {};
  if (b.add) { const label = (b.add || '').trim(); if (!label) return res.status(400).json({ error: 'Label required' }); const sort = (db.prepare(`SELECT COALESCE(MAX(sort),0) m FROM shift_tasks`).get().m) + 1; db.prepare(`INSERT INTO shift_tasks (label, sort) VALUES (?, ?)`).run(label.slice(0, 120), sort); }
  else if (b.remove) db.prepare(`UPDATE shift_tasks SET active = 0 WHERE id = ?`).run(+b.remove);
  res.json({ ok: true });
});

/* ---------------- Client Voice — everything clients tell us from the kiosk ---------------- */
const CV_DAYS = { today: 1, '7': 7, '30': 30, all: 3650 };
app.get('/api/client-voice', requireAuth, (req, res) => {
  const days = CV_DAYS[req.query.range] || 30;
  const since = `datetime('now','-${days} day')`, sinceD = `date('now','-${days} day')`;
  const reachouts = db.prepare(`SELECT r.id, r.text, r.priority, r.status, substr(r.created_at,1,16) at, c.pref, c.name
    FROM requests r LEFT JOIN clients c ON c.id=r.client_id
    WHERE r.created_by_name='Client (kiosk)' AND r.department<>'Suggestion box' AND r.created_at>=${since}${facCtx(req).frag('r.facility_id')} ORDER BY r.id DESC LIMIT 60`).all();
  const suggestions = db.prepare(`SELECT r.id, r.text, r.status, substr(r.created_at,1,16) at, c.pref
    FROM requests r LEFT JOIN clients c ON c.id=r.client_id WHERE r.department='Suggestion box' AND r.created_at>=${since}${facCtx(req).frag('r.facility_id')} ORDER BY r.id DESC LIMIT 40`).all();
  const surveys = db.prepare(`SELECT sr.id, substr(sr.created_at,1,16) at, c.pref, c.name, ROUND(AVG(sa.value_num),1) score, GROUP_CONCAT(sa.value_text,' · ') comments
    FROM survey_responses sr LEFT JOIN clients c ON c.id=sr.client_id LEFT JOIN survey_answers sa ON sa.response_id=sr.id
    WHERE sr.created_at>=${since}${facCtx(req).frag('c.facility_id')} GROUP BY sr.id ORDER BY sr.id DESC LIMIT 40`).all();
  const meals = db.prepare(`SELECT mf.meal_date, mf.meal, mf.dish, mf.comment, c.pref
    FROM meal_feedback mf LEFT JOIN clients c ON c.id = mf.client_id WHERE mf.created_at>=${since} AND mf.comment IS NOT NULL AND mf.comment<>''${facCtx(req).frag('c.facility_id')} ORDER BY mf.id DESC LIMIT 40`).all();
  const openReach = db.prepare(`SELECT COUNT(*) n FROM requests WHERE created_by_name='Client (kiosk)' AND status<>'Done'${facCtx(req).frag('facility_id')}`).get().n;
  const sc = db.prepare(`SELECT AVG(sa.value_num) a FROM survey_answers sa JOIN survey_responses sr ON sr.id=sa.response_id LEFT JOIN clients c ON c.id=sr.client_id WHERE sa.value_num IS NOT NULL AND sr.created_at>=${since}${facCtx(req).frag('c.facility_id')}`).get().a;
  const mlk = db.prepare(`SELECT AVG(liked) a FROM meal_feedback WHERE liked IS NOT NULL AND created_at>=${since}`).get().a;
  // Mark as seen now (clears the "new" badge for this user).
  setState('cv_seen_' + req.user.id, new Date().toISOString().replace('T', ' ').slice(0, 19));
  res.json({ range: req.query.range || '30', reachouts, suggestions, surveys, meals, kpi: { openReach, expScore: sc != null ? Math.round(sc * 10) / 10 : null, mealLiked: mlk != null ? Math.round(mlk * 100) : null } });
});
// Count of new kiosk feedback since this user last opened Client Voice (for the badge).
app.get('/api/client-voice/unseen', requireAuth, (req, res) => {
  const seen = getState('cv_seen_' + req.user.id) || '1970-01-01';
  const cvFc = facCtx(req); if (denyFac(cvFc, res)) return;
  const c1 = db.prepare(`SELECT COUNT(*) n FROM requests WHERE created_by_name='Client (kiosk)' AND created_at>?${cvFc.frag('facility_id')}`).get(seen).n;
  const c2 = db.prepare(`SELECT COUNT(*) n FROM survey_responses sr LEFT JOIN clients c ON c.id=sr.client_id WHERE sr.created_at>?${cvFc.frag('c.facility_id')}`).get(seen).n;
  const c3 = db.prepare(`SELECT COUNT(*) n FROM meal_feedback mf LEFT JOIN clients c ON c.id=mf.client_id WHERE mf.created_at>? AND mf.comment IS NOT NULL AND mf.comment<>''${cvFc.frag('c.facility_id')}`).get(seen).n;
  res.json({ unseen: c1 + c2 + c3 });
});

/* ---------------- Shift report (the pass-down) ---------------- */
function shiftReportCtx() {
  const today = appToday(), sh = currentShift();
  const current = db.prepare(`SELECT * FROM shift_reports WHERE shift_date = ? AND shift = ?`).get(today, sh) || null;
  const previous = db.prepare(`SELECT * FROM shift_reports WHERE NOT (shift_date = ? AND shift = ?) ORDER BY created_at DESC LIMIT 1`).get(today, sh) || null;
  // Suggested counts so the writer confirms rather than tallies from scratch.
  const dcToday = db.prepare(`SELECT COUNT(*) n FROM clients WHERE substr(discharge_date,1,10) = ?`).get(today).n;
  const incToday = db.prepare(`SELECT COUNT(*) n FROM incidents WHERE substr(created_at,1,10) = ?`).get(today).n;
  const suggest = { census: censusNow(), discharges: dcToday, incidents: incToday };
  return { shift: sh, shift_date: today, current, previous, suggest };
}
app.get('/api/shift-report', requireAuth, (req, res) => res.json(shiftReportCtx()));
app.get('/api/shift-report/history', requireAuth, (req, res) => res.json({ reports: db.prepare(`SELECT * FROM shift_reports ORDER BY created_at DESC LIMIT 15`).all() }));
app.post('/api/shift-report', requireAuth, (req, res) => {
  const b = req.body || {}; const today = appToday(), sh = currentShift();
  const data = (b.data && typeof b.data === 'object') ? JSON.stringify(b.data) : null;
  // Keep the legacy columns populated from the structured answers for list previews.
  const d = b.data || {};
  const summary = (b.summary || d.notes || d.summary || '').trim() || null;
  const watch = (b.watch || d.watch || '').trim() || null;
  const followups = (b.followups || d.followups || '').trim() || null;
  db.prepare(`INSERT INTO shift_reports (shift_date, shift, summary, watch, followups, data, census, by_id, by_name)
    VALUES (?,?,?,?,?,?,?,?,?)
    ON CONFLICT(shift_date, shift) DO UPDATE SET summary=excluded.summary, watch=excluded.watch, followups=excluded.followups, data=excluded.data, census=excluded.census, by_id=excluded.by_id, by_name=excluded.by_name, updated_at=datetime('now')`)
    .run(today, sh, summary, watch, followups, data, (d.census != null && d.census !== '') ? parseInt(d.census, 10) || 0 : censusNow(), req.user.id, req.user.name);
  audit({ user: req.user, action: 'SHIFT_REPORT', detail: `${sh} ${today}`, ip: req.ip });
  res.json({ ok: true });
});
