// Owner-level accountability: per therapist / case manager — caseload, chart
// completeness, care-card completion, and outcomes (AMA rate, avg LOS).
app.get('/api/accountability/owners', requireAuth, requireAdmin, (req, res) => {
  const active = db.prepare(`SELECT id, therapist, case_manager, loc, diagnosis, insurance, touch, prefs, anchor_why, doc_forms FROM clients WHERE active = 1 AND discharge_status IS NULL`).all();
  const chartComplete = (c) => { let f = {}; try { f = c.doc_forms ? JSON.parse(c.doc_forms) : {}; } catch { f = {}; } return !!(c.loc && c.loc !== 'Unspecified') && !!c.diagnosis && !!c.insurance && !!f.biopsych && !!f.tx_plan; };
  const ccComplete = (c) => !!(c.touch && c.prefs && c.anchor_why);
  const agg = (field) => {
    const m = {};
    for (const c of active) { const who = (c[field] || '').trim(); if (!who) continue; const e = m[who] || (m[who] = { owner: who, caseload: 0, chart: 0, cc: 0 }); e.caseload++; if (chartComplete(c)) e.chart++; if (ccComplete(c)) e.cc++; }
    return Object.values(m).map((e) => ({ ...e, chartPct: Math.round(e.chart / e.caseload * 100), ccPct: Math.round(e.cc / e.caseload * 100) })).sort((a, b) => a.chartPct - b.chartPct);
  };
  const a = buildAnalytics(90);
  const oT = {}, oC = {};
  for (const t of a.byTherapist) oT[t.key] = t;
  for (const t of a.byCaseManager) oC[t.key] = t;
  const merge = (rows, outc) => rows.map((e) => ({ ...e, amaRate: outc[e.owner]?.amaRate ?? null, avgLos: outc[e.owner]?.avgLos ?? null, discharges: outc[e.owner]?.n ?? 0 }));
  res.json({ caseload: active.length, unassignedTherapist: active.filter((c) => !c.therapist).length, unassignedCM: active.filter((c) => !c.case_manager).length, byTherapist: merge(agg('therapist'), oT), byCaseManager: merge(agg('case_manager'), oC) });
});

// ---- Care Card completion: the hospitality layer ON TOP of the Kipu chart.
// Every new admit must have it filled within the first hour so we can care for
// them by their preferences right away. (Identity comes from Kipu — single
// source of truth; staff fill the preferences.) ----
const CARECARD_CORE = [
  { key: 'touch', label: 'Personal touch' },
  { key: 'prefs', label: 'Preferences' },
  { key: 'anchor_why', label: 'Intake anchor (why they came)' },
];
const CARECARD_DUE_MIN = +(process.env.CARECARD_DUE_MIN || 60);
function careCardStatus(c) {
  const missing = CARECARD_CORE.filter((f) => !(c[f.key] && String(c[f.key]).trim())).map((f) => f.label);
  return { complete: missing.length === 0, missing };
}
function careCardMinsSinceAdmit(c) {
  if (!c.admit) return null;
  const ts = Date.parse(String(c.admit).slice(0, 10) + 'T' + (c.admit_time && /^\d{2}:\d{2}/.test(c.admit_time) ? c.admit_time.slice(0, 5) : '00:00') + ':00');
  return Number.isNaN(ts) ? null : Math.floor((Date.now() - ts) / 60000);
}
app.get('/api/carecards', requireAuth, (req, res) => {
  const fc = facCtx(req); if (denyFac(fc, res)) return;
  const active = db.prepare(`SELECT id, pref, name, room, program, loc, admit, admit_time, touch, prefs, anchor_why, goals, triggers, safety FROM clients WHERE active = 1 AND discharge_status IS NULL${fc.frag('facility_id')} ORDER BY admit DESC, room`).all();
  const rows = active.map((c) => {
    const st = careCardStatus(c);
    const mins = careCardMinsSinceAdmit(c);
    return { id: c.id, name: c.pref || c.name, room: c.room, loc: c.loc, admit: c.admit, minsSinceAdmit: mins,
      complete: st.complete, missing: st.missing, overdue: !st.complete && mins != null && mins > CARECARD_DUE_MIN };
  });
  res.json({
    dueMin: CARECARD_DUE_MIN, total: rows.length,
    complete: rows.filter((r) => r.complete).length,
    incomplete: rows.filter((r) => !r.complete),
    overdue: rows.filter((r) => r.overdue).length,
  });
});

// ---- Documentation compliance: % of required Kipu fields completed, per SLA,
// with the overdue clients named. Turns "is the chart complete?" into a score. ----
const DOC_REQS = [
  { key: 'loc', label: 'Level of care (ASAM)', slaHrs: 1, has: (c) => c.loc && c.loc !== 'Unspecified' },
  { key: 'diagnosis', label: 'Diagnosis', slaHrs: 24, has: (c) => !!c.diagnosis },
  { key: 'insurance', label: 'Insurance', slaHrs: 24, has: (c) => !!c.insurance },
  { key: 'therapist', label: 'Primary therapist', slaHrs: 24, has: (c) => !!c.therapist },
  { key: 'case_manager', label: 'Case manager', slaHrs: 24, has: (c) => !!c.case_manager },
  { key: 'referral_source', label: 'Referral source', slaHrs: 24, has: (c) => !!c.referral_source },
  // These are verified by the ACTUAL Kipu chart form (doc_forms), not inferred.
  { key: 'biopsych', label: 'Biopsychosocial', slaHrs: 24, form: 'biopsych' },
  { key: 'tx_plan', label: 'Treatment plan', slaHrs: 72, form: 'tx_plan' },
  { key: 'asam', label: 'ASAM / level-of-care assessment', slaHrs: 72, form: 'asam' },
  { key: 'cm_note', label: 'Case-management note', slaHrs: 24, form: 'cm_note' },
];
app.get('/api/compliance', requireAuth, requireAdmin, (req, res) => {
  const fc = facCtx(req); if (denyFac(fc, res)) return;
  const clients = db.prepare(`SELECT id, pref, name, room, admit, admit_time, loc, diagnosis, insurance, therapist, case_manager, referral_source, doc_forms FROM clients WHERE active = 1 AND discharge_status IS NULL${fc.frag('facility_id')}`).all();
  const formsByClient = {};
  for (const c of clients) { try { formsByClient[c.id] = c.doc_forms ? JSON.parse(c.doc_forms) : null; } catch { formsByClient[c.id] = null; } }
  const out = DOC_REQS.map((rq) => {
    let complete = 0, applicable = 0; const overdue = [], missing = [];
    for (const c of clients) {
      let ok;
      if (rq.form) { const f = formsByClient[c.id]; if (f == null) continue; applicable++; ok = !!f[rq.form]; }   // chart-verified
      else { applicable++; ok = !!rq.has(c); }
      if (ok) { complete++; continue; }
      const m = careCardMinsSinceAdmit(c);
      const row = { id: c.id, name: c.pref || c.name, room: c.room, mins: m };
      missing.push(row);
      if (m == null || m > rq.slaHrs * 60) overdue.push(row);
    }
    return { key: rq.key, label: rq.label, slaHrs: rq.slaHrs, complete, total: applicable, pct: applicable ? Math.round(complete / applicable * 100) : null, overdueCount: overdue.length, overdue: overdue.slice(0, 30), missing: missing.slice(0, 30) };
  });
  const totC = out.reduce((s, r) => s + r.complete, 0), totT = out.reduce((s, r) => s + r.total, 0);
  res.json({ clients: clients.length, score: totT ? Math.round(totC / totT * 100) : null, fields: out });
});

// "Did the person actually complete an admission, or were they referred out before
// finishing intake?" A record discharged within ~a day of admit (or with no admit
// at all) AND with no documentation (no therapist/diagnosis, no real discharge
// write-up) is a referral-out / incomplete intake — NOT a real admit+discharge. We
// keep those out of the real counts and label them honestly. Threshold is tunable.
function incompleteStayDays() { const n = parseInt(getState('incomplete_stay_days') || '1', 10); return Number.isFinite(n) && n >= 0 ? n : 1; }
function isReferredOut(c) {
  const a = (c.admit || '').slice(0, 10), d = (c.discharge_date || '').slice(0, 10);
  if (!d) return false;   // not discharged → still here / a normal active stay
  const documented = [c.therapist, c.diagnosis].some((x) => x && String(x).trim())
    || (c.discharge_reason && !/unable to determine|no documentation/i.test(String(c.discharge_reason)));
  if (documented) return false;   // real documentation → treat as a genuine stay
  if (!a) return true;            // discharged with no admit ever recorded → never truly admitted
  const days = Math.round((Date.parse(d) - Date.parse(a)) / 86400000);
  return days >= 0 && days <= incompleteStayDays();
}
// Build the nightly census (the in-app equal of the manual email) as HTML+text.
// `reportDate` is the day being summarized — intakes/discharges/LOC-changes are
// keyed to it. Defaults to today (manual mid-day sends); the midnight cutoff
// passes YESTERDAY so the email reflects the day that just finished, not the new
// empty one. The census/LOC breakdown is the current point-in-time snapshot.
function buildCensusReport(reportDate = appToday(), fid = null, facName = '') {
  // Per-building report: rows with no facility stamp are legacy Akron detox
  // (owner's standing rule), so the default building tolerates NULL.
  const cf = fid ? ` AND (facility_id = ${+fid}${+fid === defaultFacilityId() ? ' OR facility_id IS NULL' : ''})` : '';
  const active = db.prepare(`SELECT id, pref, name, program, loc, admit FROM clients WHERE active = 1 AND discharge_status IS NULL${cf}`).all();
  const byLoc = {};
  for (const c of active) { const k = (c.loc && c.loc !== 'Unspecified') ? c.loc : (parseLoc(c.program) || 'Unspecified'); byLoc[k] = (byLoc[k] || 0) + 1; }
  const rows = Object.entries(byLoc).map(([code, n]) => ({ code, label: LOC_LABEL[code] || code, n })).sort((a, b) => (LOC_RANK[b.code] ?? -1) - (LOC_RANK[a.code] ?? -1));
  // De-dupe by person: the same patient can have multiple client rows (re-admission
  // casefiles or unmatched sync inserts) — show each person once in the email.
  const cnorm = (s) => String(s || '').toLowerCase().replace(/[^a-z ]/g, '').replace(/\s+/g, ' ').trim();
  const cKey = (c) => (c.kipu_id ? String(c.kipu_id).split(':')[0] : '') || cnorm(c.name);
  const cDedupe = (rows) => { const seen = new Set(); const out = []; for (const c of rows) { const k = cKey(c); if (k && seen.has(k)) continue; if (k) seen.add(k); out.push(c); } return out; };
  // Split out referral-outs / incomplete intakes so they don't inflate Intakes/Discharges.
  const refKeys = new Set(); const referredOut = [];
  const intakeRows = cDedupe(db.prepare(`SELECT pref, name, kipu_id, admit, admit_time, discharge_date, discharge_status, discharge_reason, therapist, diagnosis FROM clients WHERE substr(admit,1,10) = ?${cf}`).all(reportDate));
  const intakes = [];
  for (const c of intakeRows) { if (isReferredOut(c)) { const k = cKey(c); if (!refKeys.has(k)) { refKeys.add(k); referredOut.push(c); } } else intakes.push(c.pref || c.name); }
  const dcRows = cDedupe(db.prepare(`SELECT pref, name, kipu_id, admit, admit_time, discharge_date, discharge_status, discharge_reason, therapist, diagnosis FROM clients WHERE substr(discharge_date,1,10) = ?${cf}
    ORDER BY (discharge_reason IS NOT NULL AND discharge_reason != '') DESC, id`).all(reportDate));
  const dcs = [];
  for (const c of dcRows) { if (isReferredOut(c)) { const k = cKey(c); if (!refKeys.has(k)) { refKeys.add(k); referredOut.push(c); } } else dcs.push(c); }
  // Discharges in the last 7 days that were debriefed but had NO in-stay
  // documentation — a standing compliance nudge to chase progress/discharge notes.
  const docGapWeek = cDedupe(db.prepare(`SELECT pref, name, kipu_id, discharge_date FROM clients
    WHERE discharge_doc_gap = 1 AND substr(discharge_date,1,10) >= date(?, '-6 day') AND substr(discharge_date,1,10) <= ?${cf}
    ORDER BY discharge_date DESC`).all(reportDate, reportDate));
  const locChanges = db.prepare(`SELECT c.pref, c.name, e.from_loc, e.to_loc FROM flow_events e LEFT JOIN clients c ON c.id = e.client_id
    WHERE e.kind = 'loc_change' AND e.date = ?${cf.replace(/facility_id/g, 'c.facility_id')} ORDER BY e.id`).all(reportDate);
  const sendouts = db.prepare(`SELECT client_name, destination, reason FROM medical_sendouts WHERE status = 'out'${cf}`).all();
  const esc = (s) => String(s == null ? '' : s).replace(/[&<>]/g, (m) => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;' }[m]));
  const dt = new Date(reportDate + 'T12:00:00').toLocaleDateString('en-US', { timeZone: APP_TZ, weekday: 'long', month: 'long', day: 'numeric' });
  const locLine = (x) => `${esc(x.pref || x.name || 'A client')} — ${esc(x.from_loc || '?')} → ${esc(x.to_loc || '?')}`;
  const losDays = (a, d) => { a = (a || '').slice(0, 10); d = (d || '').slice(0, 10); if (!a || !d) return null; const n = Math.round((Date.parse(d) - Date.parse(a)) / 864e5); return n >= 0 ? n : null; };
  const t12 = (hhmm) => { const m = String(hhmm || '').match(/^(\d{1,2}):(\d{2})/); if (!m) return ''; let h = +m[1]; const ap = h >= 12 ? 'PM' : 'AM'; h = h % 12 || 12; return `${h}:${m[2]} ${ap}`; };
  // "In & out" for a referral-out: when they arrived + how long before they left.
  const inOut = (c) => { const t = t12(c.admit_time), l = losDays(c.admit, c.discharge_date); const parts = []; if (t) parts.push(`in ${t}`); if (l != null) parts.push(l === 0 ? 'out same day' : `${l} day${l === 1 ? '' : 's'}`); return parts.join(' · '); };
  const html = `<div style="font-family:Georgia,serif;color:#1b2825;max-width:560px">
    <h2 style="font-family:Georgia,serif">Daily Census &amp; Activity</h2>
    <p style="color:#666;margin:0 0 10px">End-of-day summary for <strong>${dt}</strong>${facName ? ` — ${esc(facName)}` : ''}</p>
    ${rows.map((r) => `<div><strong>${esc(r.code)}</strong> ${esc(r.label.replace(r.code + ' · ', ''))} — <strong>${r.n}</strong></div>`).join('')}
    <div style="border-top:2px solid #ccc;margin-top:6px;padding-top:6px"><strong>TOTAL CENSUS — ${active.length}</strong></div>
    <h3>Intakes</h3>${intakes.length ? intakes.map((n) => `<div>• ${esc(n)}</div>`).join('') : '<div>ZERO</div>'}
    <h3>Discharges</h3>${dcs.length ? dcs.map((d) => { const l = losDays(d.admit, d.discharge_date); return `<div>• ${esc(d.pref || d.name)} — ${esc(d.discharge_status || '')}${l != null ? ` · LOS ${l} day${l === 1 ? '' : 's'}` : ''}${d.discharge_reason ? ' · ' + esc(d.discharge_reason) : ''}</div>`; }).join('') : '<div>ZERO</div>'}
    ${referredOut.length ? `<h3>Referred out / didn't complete intake</h3><p style="color:#888;font-size:12px;margin:0 0 4px">Came in but were referred elsewhere before completing intake — not counted as admissions or discharges.</p>${referredOut.map((c) => { const io = inOut(c); return `<div>• ${esc(c.pref || c.name)}${io ? ` — ${esc(io)}` : ''}${c.discharge_status && c.discharge_status !== 'Merged (duplicate)' ? ` (${esc(c.discharge_status)})` : ''}</div>`; }).join('')}` : ''}
    <h3>LOC changes</h3>${locChanges.length ? locChanges.map((x) => `<div>• ${locLine(x)}</div>`).join('') : '<div>ZERO</div>'}
    ${docGapWeek.length ? `<h3 style="color:#a60">⚠ Documentation gap — chase before month-end</h3><p style="color:#888;font-size:12px;margin:0 0 4px">${docGapWeek.length} discharge${docGapWeek.length === 1 ? '' : 's'} in the last 7 days had no progress or discharge notes in the chart — only intake paperwork. The reason for leaving couldn't be determined and this is a billing/audit risk.</p>${docGapWeek.map((c) => `<div>• ${esc(c.pref || c.name)} <span style="color:#888">· discharged ${esc((c.discharge_date || '').slice(0, 10))}</span></div>`).join('')}` : ''}
    ${sendouts.length ? `<h3>Other (medical send-outs)</h3>${sendouts.map((s) => `<div>• ${esc(s.client_name)} — ${esc(s.destination || 'sent out')}${s.reason ? ': ' + esc(s.reason) : ''}</div>`).join('')}` : ''}
    <p style="color:#888;font-size:12px">Generated by Armada Care Standards.</p></div>`;
  const text = `Daily Census & Activity — ${dt}\n` + rows.map((r) => `${r.code}: ${r.n}`).join('\n') + `\nTOTAL: ${active.length}`
    + `\nIntakes: ${intakes.join(', ') || 'ZERO'}`
    + `\nDischarges: ${dcs.map((d) => { const l = losDays(d.admit, d.discharge_date); return (d.pref || d.name) + ' — ' + (d.discharge_status || '') + (l != null ? ` (LOS ${l}d)` : ''); }).join('; ') || 'ZERO'}`
    + (referredOut.length ? `\nReferred out / didn't complete intake: ${referredOut.map((c) => { const io = inOut(c); return (c.pref || c.name) + (io ? ` (${io})` : ''); }).join('; ')}` : '')
    + `\nLOC changes: ${locChanges.map((x) => (x.pref || x.name || 'A client') + ' ' + (x.from_loc || '?') + '→' + (x.to_loc || '?')).join('; ') || 'ZERO'}`
    + (docGapWeek.length ? `\n⚠ Documentation gap (7d, chase before month-end): ${docGapWeek.map((c) => (c.pref || c.name) + ' (disch ' + (c.discharge_date || '').slice(0, 10) + ')').join('; ')}` : '');
  return { subject: `Daily Census — ${facName ? facName + ' — ' : ''}${dt} (${active.length})`, html, text, total: active.length };
}
async function sendCensusEmail(reportDate = appToday(), fid = null) {
  // Per-facility recipients come from the building's ⚙️ report_email setting;
  // the org-wide report (and the default building) falls back to the global list.
  const fac = fid ? orgFacilities().find((f) => f.id === +fid) : null;
  const to = ((fid && facSetting(+fid, 'report_email')) || getState('census_email_to') || process.env.CENSUS_EMAIL_TO || process.env.REPORT_TO || '').trim();
  if (!emailConfigured()) return { sent: false, reason: 'email not connected — Settings → Email' };
  if (!to) return { sent: false, reason: 'no recipients set — add them under Recipients…' };
  const r = buildCensusReport(reportDate, fid ? +fid : null, fac?.name || '');
  await sendEmail({ to, subject: r.subject, html: r.html });
  return { sent: true, to, facility: fac?.name };
}
// Midnight fan-out: one report per building that had people or activity that
// day. A building only mails if it has its own report_email set — except the
// default (Akron detox) building, which keeps the legacy global recipient list
// so the owner's nightly email never silently stops.
async function sendCensusEmailsAll(reportDate) {
  const dfid = defaultFacilityId();
  const fids = db.prepare(`SELECT DISTINCT COALESCE(facility_id, ?) AS fid FROM clients
    WHERE (active = 1 AND discharge_status IS NULL) OR substr(admit,1,10) = ? OR substr(discharge_date,1,10) = ?`)
    .all(dfid || 0, reportDate, reportDate).map((r) => r.fid).filter(Boolean);
  const out = [];
  for (const fid of fids) {
    const to = (facSetting(fid, 'report_email') || (fid === dfid ? (getState('census_email_to') || process.env.CENSUS_EMAIL_TO || '') : '')).trim();
    if (!to) continue;
    try { out.push(await sendCensusEmail(reportDate, fid)); }
    catch (e) { console.error('[census fan-out]', fid, e.message); out.push({ sent: false, reason: e.message }); }
  }
  return out;
}
app.post('/api/command/census/email', requireAuth, requireAdmin, async (req, res) => {
  // Optional scope: 'yesterday' (the end-of-day summary, same as the midnight run)
  // or an explicit YYYY-MM-DD. Default is today (a live mid-day snapshot).
  let reportDate = appToday();
  const b = req.body || {};
  if (b.scope === 'yesterday') reportDate = addDays(appToday(), -1);
  else if (typeof b.date === 'string' && /^\d{4}-\d{2}-\d{2}$/.test(b.date)) reportDate = b.date;
  // The chip scopes the manual send: pick a building → that building's report
  // (to its report_email if set, else the global list). No pick → org-wide.
  const fc = facCtx(req); if (denyFac(fc, res)) return;
  try { const r = await sendCensusEmail(reportDate, fc.one); res.json({ ...r, date: reportDate }); } catch (e) { res.status(502).json({ error: e.message }); }
});
