// Detox Watch: active clients with moderate/severe withdrawal or med concerns.
app.get('/api/detox-watch', requireAuth, (req, res) => {
  const clients = db.prepare(`SELECT id, pref, name, room FROM clients WHERE active = 1 AND discharge_status IS NULL${facCtx(req).frag('facility_id')}`).all();
  const rank = { Severe: 0, Moderate: 1 };
  const watch = [];
  for (const c of clients) {
    const a = latestAmaRead(c.id);
    if (!a) continue;
    const med = safeArr(a.med_concerns);
    const w = a.withdrawal_level;
    if ((w && ['Moderate', 'Severe'].includes(w)) || med.length) {
      watch.push({ id: c.id, name: c.pref || c.name, room: c.room, withdrawal_level: w || 'Unknown', withdrawal: a.withdrawal_note || '', med_concerns: med });
    }
  }
  watch.sort((x, y) => (rank[x.withdrawal_level] ?? 9) - (rank[y.withdrawal_level] ?? 9) || y.med_concerns.length - x.med_concerns.length);
  res.json({ watch });
});
app.get('/api/discharge-learnings', requireAuth, (req, res) => {
  const rows = db.prepare(`SELECT id, pref, name, discharge_status, discharge_date, discharge_reason, discharge_evidence, discharge_doc_gap, discharge_improve
    FROM clients WHERE discharge_status IS NOT NULL AND discharge_date >= date('now','-60 day')${facCtx(req).frag('facility_id')}
    ORDER BY discharge_date DESC LIMIT 60`).all();
  const docGap = rows.filter((r) => r.discharge_doc_gap).length;
  res.json({ discharges: rows, docGap, total: rows.length });
});

// ---- Leadership Command Center (admin/leadership only) ----
// One screen that operationalizes the Clinical Director's daily review: flow,
// the 3.2-WM step-down clock, discharge planning, documentation compliance,
// staffing coverage — every number pulled live from Kipu where we have it.
function daysSince(s) {
  if (!s) return null;
  const t = Date.parse(String(s).length <= 10 ? s + 'T00:00:00' : s);
  if (Number.isNaN(t)) return null;
  return Math.floor((Date.now() - t) / 864e5);
}
const isDetoxProgram = (p) => /detox|withdrawal|\bwm\b|3\.?2|3\.?7/i.test(p || '');

// REAL discharge count over a window: distinct stays (person + admit date), excluding
// retired duplicates, referral-outs, and phantoms (a "discharge" for someone who is
// still an active patient never happened). Shared by every discharge tile/metric so
// none of them can show the census-churn inflation.
function realDischargeCount(sinceDate, untilDate) {
  const norm = (s) => String(s || '').toLowerCase().replace(/[^a-z ]/g, '').replace(/\s+/g, ' ').trim();
  const keyOf = (c) => (c.kipu_id ? String(c.kipu_id).split(':')[0] : '') || norm(c.name);
  const activeKeys = new Set(db.prepare(`SELECT kipu_id, name FROM clients WHERE active = 1 AND discharge_status IS NULL AND merged_into IS NULL`).all().map(keyOf));
  const rows = db.prepare(`SELECT pref, name, kipu_id, admit, discharge_date, discharge_reason, therapist, diagnosis FROM clients
    WHERE merged_into IS NULL AND COALESCE(discharge_status,'') != 'Merged (duplicate)' AND discharge_date IS NOT NULL AND substr(discharge_date,1,10) >= ?`).all(sinceDate);
  const seen = new Set(); let n = 0;
  for (const c of rows) {
    if (untilDate && (c.discharge_date || '').slice(0, 10) > untilDate) continue;   // window end
    const k = keyOf(c) + '|' + (c.admit || '').slice(0, 10);
    if (seen.has(k)) continue; seen.add(k);
    if (isReferredOut(c)) continue;            // didn't complete intake
    if (activeKeys.has(keyOf(c))) continue;    // phantom — person is still here
    n++;
  }
  return n;
}

app.get('/api/command/overview', requireAuth, requireAdmin, (req, res) => {
  const today = appToday();
  const fc = facCtx(req); if (denyFac(fc, res)) return;
  const active = db.prepare(`SELECT id, pref, name, room, program, loc, admit, next_loc, anticipated_dc, interests FROM clients WHERE active = 1 AND discharge_status IS NULL${fc.frag('facility_id')} ORDER BY room, name`).all();

  // Flow
  const admitsToday = active.filter((c) => (c.admit || '').slice(0, 10) === today).length;
  const admitsTodayList = active.filter((c) => (c.admit || '').slice(0, 10) === today).map((c) => ({ name: c.pref || c.name, loc: c.loc && c.loc !== 'Unspecified' ? c.loc : (parseLoc(c.program) || '') }));
  const discharges7d = realDischargeCount(addDays(today, -7));
  // De-dupe by person: the same patient can have several client rows (re-admission
  // casefiles, or unmatched sync inserts) that all got stamped "discharged today"
  // when they dropped off the census in one sync — show each person once.
  const dnorm = (s) => String(s || '').toLowerCase().replace(/[^a-z ]/g, '').replace(/\s+/g, ' ').trim();
  const personKey = (c) => (c.kipu_id ? String(c.kipu_id).split(':')[0] : '') || dnorm(c.name) || ('id' + c.id);
  const dedupeByPerson = (rows, keyExtra = () => '') => {
    const seen = new Set(); const out = [];
    for (const c of rows) { const k = personKey(c) + '|' + keyExtra(c); if (seen.has(k)) continue; seen.add(k); out.push(c); }
    return out;
  };
  const dtRaw = db.prepare(`SELECT id, pref, name, kipu_id, admit, discharge_date, discharge_status, discharge_reason, therapist, diagnosis, facility_id FROM clients
    WHERE merged_into IS NULL AND substr(discharge_date,1,10) = ?${fc.frag('facility_id')}
    ORDER BY (discharge_reason IS NOT NULL AND discharge_reason != '') DESC, id`).all(today);
  const dtDeduped = dedupeByPerson(dtRaw);
  // People currently here — a "discharge" for one of them is a phantom (still active).
  const activeKeySet = new Set(db.prepare(`SELECT kipu_id, name FROM clients WHERE active = 1 AND discharge_status IS NULL AND merged_into IS NULL`).all().map((c) => (c.kipu_id ? String(c.kipu_id).split(':')[0] : '') || dnorm(c.name)));
  // Referral-outs and phantoms are not real discharges — split them out.
  const dischargesTodayList = dtDeduped.filter((c) => !isReferredOut(c) && !activeKeySet.has(personKey(c))).map((c) => ({ id: c.id, name: c.pref || c.name, status: c.discharge_status || '', reason: c.discharge_reason || '' }));
  const dischargesToday = dischargesTodayList.length;
  const referredOutTodayList = dtDeduped.filter((c) => isReferredOut(c)).map((c) => ({ id: c.id, name: c.pref || c.name, status: c.discharge_status || '' }));
  const referredOutToday = referredOutTodayList.length;
  // Recent discharges (3 days) so a just-after-midnight view still shows them.
  const drRaw = db.prepare(`SELECT id, pref, name, kipu_id, discharge_status, discharge_reason, substr(discharge_date,1,10) d
    FROM clients WHERE discharge_status IS NOT NULL AND discharge_date >= date('now','-3 day')${fc.frag('facility_id')} ORDER BY discharge_date DESC`).all();
  const dischargesRecentList = dedupeByPerson(drRaw, (c) => c.d).map((c) => ({ id: c.id, name: c.pref || c.name, status: c.discharge_status || '', reason: c.discharge_reason || '', date: c.d }));
  const sendoutsActive = db.prepare(`SELECT client_name, destination, reason FROM medical_sendouts WHERE status = 'out' ORDER BY sent_at DESC`).all();

  // Per-client latest read, computed once.
  const enriched = active.map((c) => {
    const a = latestAmaRead(c.id);
    return {
      id: c.id, name: c.pref || c.name, room: c.room, program: c.program, admit: c.admit,
      loc: c.loc && c.loc !== 'Unspecified' ? c.loc : (parseLoc(c.program) || 'Unspecified'),
      los: daysSince(c.admit),
      level: a?.level || null,
      // Prefer Kipu's structured next-level-of-care + anticipated date; fall back
      // to what the AI inferred from the notes.
      step_down: c.next_loc ? (parseLoc(c.next_loc) !== 'Unspecified' ? parseLoc(c.next_loc) : c.next_loc) : (a?.step_down || 'Unknown'),
      transport: a?.transport || 'Unknown',
      anticipated_dc: c.anticipated_dc || a?.anticipated_dc || '',
      discharge_plan: a?.discharge_plan || '',
      doc_flags: a ? safeArr(a.doc_flags) : [],
      withdrawal_level: a?.withdrawal_level || null,
    };
  });

  // 3.2-WM step-down clock: detox clients, with the >4-day flag.
  const detox = enriched.filter((c) => isDetoxProgram(c.program))
    .map((c) => ({ ...c, overdue: c.los != null && c.los > 4 }))
    .sort((a, b) => (b.los ?? -1) - (a.los ?? -1));

  // Discharge planning
  const stepDownCounts = {};
  enriched.forEach((c) => { stepDownCounts[c.step_down] = (stepDownCounts[c.step_down] || 0) + 1; });
  const transportNeeded = enriched.filter((c) => c.transport === 'Needed');
  const undecided = enriched.filter((c) => c.step_down === 'Undecided');
  const anticipated = enriched.filter((c) => c.anticipated_dc).map((c) => ({ id: c.id, name: c.name, room: c.room, when: c.anticipated_dc, step_down: c.step_down, transport: c.transport }));

  // Documentation compliance: anyone with a flagged gap.
  const docGaps = enriched.filter((c) => c.doc_flags.length).map((c) => ({ id: c.id, name: c.name, room: c.room, flags: c.doc_flags }));
  const docClean = enriched.length - docGaps.length;

  // Staffing coverage today
  const slotsToday = db.prepare(`SELECT s.id, s.needed, s.part, s.role,
    (SELECT COUNT(*) FROM schedule_assignments a WHERE a.slot_id=s.id AND a.status='scheduled') AS sched
    FROM schedule_slots s WHERE s.date = ?`).all(today);
  const needed = slotsToday.reduce((n, s) => n + s.needed, 0);
  const scheduled = slotsToday.reduce((n, s) => n + s.sched, 0);
  const gaps = slotsToday.filter((s) => s.sched < s.needed).map((s) => ({ part: s.part, role: s.role, short: s.needed - s.sched }));
  const callOffsToday = db.prepare(`SELECT COUNT(*) n FROM schedule_assignments a JOIN schedule_slots s ON s.id=a.slot_id WHERE a.status='called_off' AND s.date = ?`).get(today).n;

  // Census by ASAM level of care: count + average length of stay per level.
  // When a client has no parseable ASAM code, fall back to their raw program
  // name so the row is meaningful (the real label) rather than "Unspecified".
  const byLoc = {};
  for (const c of enriched) {
    let key = c.loc || 'Unspecified';
    if (key === 'Unspecified' && c.program && String(c.program).trim()) key = String(c.program).trim();
    const b = byLoc[key] || (byLoc[key] = { key, count: 0, losSum: 0, losN: 0 });
    b.count++; if (c.los != null) { b.losSum += c.los; b.losN++; }
  }
  const locCensus = Object.values(byLoc)
    .map((r) => {
      const coded = LOC_RANK[r.key] != null;     // a known ASAM/pseudo level
      const fullLabel = LOC_LABEL[r.key] || r.key;
      return {
        code: coded ? r.key : '',
        label: coded ? fullLabel.replace(r.key + ' · ', '') : r.key,   // program name when uncoded
        count: r.count,
        avgLos: r.losN ? Math.round(r.losSum / r.losN * 10) / 10 : null,
      };
    })
    .sort((a, b) => (LOC_RANK[b.code] ?? -1) - (LOC_RANK[a.code] ?? -1) || b.count - a.count);

  // Step-downs: where clients have moved, over the last 30 days, by destination level.
  const stepRows = db.prepare(`SELECT from_loc, to_loc FROM flow_events WHERE kind='loc_change' AND date >= date('now','-30 day')`).all();
  const stepByDest = {};
  let stepDowns = 0, stepUps = 0;
  for (const r of stepRows) {
    const fr = LOC_RANK[r.from_loc] ?? null, to = LOC_RANK[r.to_loc] ?? null;
    if (fr != null && to != null) { if (to < fr) stepDowns++; else if (to > fr) stepUps++; }
    if (r.to_loc) { (stepByDest[r.to_loc] = stepByDest[r.to_loc] || { code: r.to_loc, label: LOC_LABEL[r.to_loc] || r.to_loc, n: 0 }).n++; }
  }
  const stepDestList = Object.values(stepByDest).sort((a, b) => b.n - a.n);

  // Daily flow snapshot — today, plus the running 14-day trend (from now on).
  rollupDailyMetrics(today);
  const todayMetrics = db.prepare(`SELECT intakes, discharges, loc_changes, ama, census FROM daily_metrics WHERE date = ?`).get(today) || { intakes: 0, discharges: 0, loc_changes: 0, ama: 0, census: active.length };
  const trend = db.prepare(`SELECT date, intakes, discharges, loc_changes, ama, census FROM daily_metrics WHERE date >= date('now','-13 day') ORDER BY date`).all();

  // Care Card completion (hospitality layer) — within the first hour of admit.
  const ccRows = db.prepare(`SELECT touch, prefs, anchor_why, admit, admit_time FROM clients WHERE active = 1 AND discharge_status IS NULL${fc.frag('facility_id')}`).all();
  let ccComplete = 0, ccOverdue = 0;
  for (const c of ccRows) { const st = careCardStatus(c); if (st.complete) ccComplete++; else { const m = careCardMinsSinceAdmit(c); if (m != null && m > CARECARD_DUE_MIN) ccOverdue++; } }
  const careCards = { total: ccRows.length, complete: ccComplete, incomplete: ccRows.length - ccComplete, overdue: ccOverdue, dueMin: CARECARD_DUE_MIN };

  // Engagement — how many clients did an activity today (boredom = AMA risk).
  const engSet = new Set(db.prepare(`SELECT DISTINCT client_id FROM activities WHERE substr(created_at,1,10) = ?`).all(today).map((r) => r.client_id));
  const engDisengaged = active.filter((c) => !engSet.has(c.id)).map((c) => ({ id: c.id, name: c.pref || c.name, room: c.room, interests: c.interests || '' }));
  const engagement = { total: active.length, engaged: active.length - engDisengaged.length, disengaged: engDisengaged, pct: active.length ? Math.round((active.length - engDisengaged.length) / active.length * 100) : null };

  // Observation-rounds compliance: how many clients are within their check window.
  const obsRows = db.prepare(`SELECT c.obs_interval, (SELECT ts FROM obs_checks o WHERE o.client_id = c.id ORDER BY o.id DESC LIMIT 1) last FROM clients c WHERE c.active = 1 AND c.discharge_status IS NULL`).all();
  const nowMs = Date.now();
  let obsOverdue = 0;
  for (const r of obsRows) { const iv = r.obs_interval || OBS_DEFAULT_MIN; const t = r.last ? Date.parse(String(r.last).replace(' ', 'T') + 'Z') : null; const m = t ? Math.floor((nowMs - t) / 60000) : null; if (m == null || m >= iv) obsOverdue++; }
  const rounds = { total: obsRows.length, overdue: obsOverdue, onTime: obsRows.length - obsOverdue, pct: obsRows.length ? Math.round((obsRows.length - obsOverdue) / obsRows.length * 100) : null };

  // Checklist progress for today
  const chk = db.prepare(`SELECT COUNT(*) total, SUM(status='done') done FROM command_checklist WHERE date = ?`).get(today);

  // Scheduled to admit today (front-desk arrivals, from Salesforce).
  const schedRows = db.prepare(`SELECT pref_or_first AS name, status FROM (
      SELECT COALESCE(NULLIF(preferred_name,''), first_name) || ' ' || last_name AS pref_or_first, status
      FROM expected_arrivals WHERE scheduled_date = ?) ORDER BY status`).all(today);
  const scheduledArrivals = {
    total: schedRows.length,
    arrived: schedRows.filter((r) => r.status === 'arrived').length,
    waiting: schedRows.filter((r) => r.status === 'expected').length,
    noShow: schedRows.filter((r) => r.status === 'no_show').length,
    list: schedRows.map((r) => ({ name: r.name, status: r.status })),
  };

  const syncedAt = getState('kipu_last_sync') || db.prepare(`SELECT max(updated_at) m FROM clients WHERE source = 'kipu'`).get()?.m || null;
  res.json({
    asOf: new Date().toISOString(),
    syncedAt,
    flow: { census: active.length, admitsToday, dischargesToday, discharges7d, admitsTodayList, dischargesTodayList, dischargesRecentList, referredOutToday, referredOutTodayList, sendouts: sendoutsActive,
      bedTotal: +(getState('detox_bed_count') || 40), bedsOpen: Math.max(0, (+(getState('detox_bed_count') || 40)) - active.length) },
    scheduled: scheduledArrivals,
    detox,
    levels: { census: locCensus, stepDowns, stepUps, stepByDest: stepDestList },
    daily: { today: todayMetrics, trend },
    planning: { stepDownCounts, transportNeeded, undecided, anticipated },
    documentation: { gaps: docGaps, clean: docClean, total: enriched.length },
    staffing: { needed, scheduled, gaps, callOffsToday, pct: needed ? Math.round(scheduled / needed * 100) : null },
    careCards,
    rounds,
    engagement,
    checklist: { total: chk?.total || 0, done: chk?.done || 0 },
  });
});

// Period summary since a given date (default: 1st of the current month).
// Pure Kipu/Salesforce data — scheduled, admitted, discharged, AMA + the
// discharge breakdown and an AMA drill-down list (reason + link to notes).
app.get('/api/command/since', requireAuth, requireAdmin, (req, res) => {
  const since = /^\d{4}-\d{2}-\d{2}$/.test(req.query.date || '') ? req.query.date : appToday().slice(0, 8) + '01';
  const endQ = /^\d{4}-\d{2}-\d{2}$/.test(req.query.end || '') ? req.query.end : null;
  const end = endQ || '9999-12-31';   // open-ended when no end date is chosen
  const fc = facCtx(req); if (denyFac(fc, res)) return;
  const scheduled = db.prepare(`SELECT status, COUNT(*) n FROM expected_arrivals WHERE scheduled_date >= ? AND scheduled_date <= ?${fc.frag('facility_id')} GROUP BY status`).all(since, end);
  const schedMap = Object.fromEntries(scheduled.map((r) => [r.status, r.n]));
  const schedTotal = scheduled.reduce((s, r) => s + r.n, 0);

  // Count distinct STAYS, not rows. A stay = one person (Kipu master id, else name) +
  // one admit date. This collapses every duplicate/phantom row of the same stay while
  // still counting a genuine re-admission (same person, a DIFFERENT admit date) as its
  // own admit/discharge. Also excludes retired duplicates and referral-outs.
  const stayKey = (c) => dupKeyOf(c) + '|' + (c.admit || '').slice(0, 10);
  const admitRows = db.prepare(`SELECT pref, name, kipu_id, facility_id, admit, discharge_date, discharge_reason, therapist, diagnosis FROM clients WHERE merged_into IS NULL AND substr(admit,1,10) >= ? AND substr(admit,1,10) <= ?${fc.frag('facility_id')}`).all(since, end);
  const seenA = new Set(); let admitted = 0;
  for (const c of admitRows) { if (isReferredOut(c)) continue; const k = stayKey(c); if (seenA.has(k)) continue; seenA.add(k); admitted++; }
  // People who are CURRENTLY here. A "discharge" for someone who is still an active
  // patient is a phantom (the census-churn bug) — they never actually left.
  const activeKeys = new Set(db.prepare(`SELECT kipu_id, name, pref, facility_id FROM clients WHERE active = 1 AND discharge_status IS NULL AND merged_into IS NULL${fc.frag('facility_id')}`).all().map((c) => dupKeyOf(c)));
  const dischRaw = db.prepare(`SELECT id, pref, name, kipu_id, facility_id, discharge_status, discharge_reason, discharge_improve, admit, discharge_date, referral_source, therapist, diagnosis
    FROM clients WHERE merged_into IS NULL AND discharge_date IS NOT NULL AND substr(discharge_date,1,10) >= ? AND substr(discharge_date,1,10) <= ?${fc.frag('facility_id')} ORDER BY discharge_date DESC`).all(since, end);
  const seenD = new Set(); const dischAll = [];
  for (const c of dischRaw) { const k = stayKey(c); if (seenD.has(k)) continue; seenD.add(k); dischAll.push(c); }
  const referredList = dischAll.filter((d) => isReferredOut(d)).map((d) => ({ id: d.id, name: d.pref || d.name, date: (d.discharge_date || '').slice(0, 10), status: d.discharge_status || '' }));
  const phantomList = dischAll.filter((d) => !isReferredOut(d) && activeKeys.has(dupKeyOf(d))).map((d) => ({ id: d.id, name: d.pref || d.name, date: (d.discharge_date || '').slice(0, 10), status: d.discharge_status || '' }));
  const dischRows = dischAll.filter((d) => !isReferredOut(d) && !activeKeys.has(dupKeyOf(d)));   // real discharges only
  const byStatus = {};
  for (const d of dischRows) { const s = d.discharge_status || 'Discharged'; byStatus[s] = (byStatus[s] || 0) + 1; }
  const losOf = (a, d) => { if (!a || !d) return null; const n = Math.round((Date.parse(d) - Date.parse(a)) / 864e5); return n >= 0 ? n : null; };
  const amaList = dischRows.filter((d) => d.discharge_status === 'AMA').map((d) => ({
    id: d.id, name: d.pref || d.name, date: (d.discharge_date || '').slice(0, 10),
    los: losOf(d.admit, d.discharge_date), reason: d.discharge_reason || '', improve: d.discharge_improve || '',
    referral: d.referral_source || '', therapist: d.therapist || '',
    hasRead: !!latestAmaRead(d.id),
  }));
  const amaCount = amaList.length;
  const losVals = dischRows.map((d) => losOf(d.admit, d.discharge_date)).filter((n) => n != null);
  const avgLos = losVals.length ? +(losVals.reduce((a, b) => a + b, 0) / losVals.length).toFixed(1) : null;
  // Every discharge in the period, clickable through to the chart.
  const dischList = dischRows.map((d) => ({
    id: d.id, name: d.pref || d.name, date: (d.discharge_date || '').slice(0, 10),
    status: d.discharge_status || 'Discharged', los: losOf(d.admit, d.discharge_date),
    reason: d.discharge_reason || d.discharge_improve || '', therapist: d.therapist || '',
    hasRead: !!latestAmaRead(d.id),
  }));

  res.json({
    since, end: endQ,
    scheduled: { total: schedTotal, arrived: schedMap.arrived || 0, noShow: schedMap.no_show || 0, expected: schedMap.expected || 0 },
    admitted,
    discharged: { total: dischRows.length, byStatus, avgLos, amaRate: dischRows.length ? Math.round(amaCount / dischRows.length * 100) : 0, list: dischList },
    ama: { count: amaCount, list: amaList },
    referredOut: { count: referredList.length, list: referredList },
    phantom: { count: phantomList.length, list: phantomList },
  });
});

// ── Admit reconciliation — the EXACT admits the app counted for a window, one row
// per person with the reasons the app-vs-Salesforce number can differ flagged on
// each: readmission (same person, second casefile), duplicate rows in the window,
// same-day discharge (chart opened but SF may mark not-admitted), manual rows.
// Read-only; built to settle "the app says 90, Salesforce says 85" by name.
// Are providers co-signing the Nurse Assessments? Scans recent admits' matching
// evaluations and reports every signature-shaped field Kipu's detail exposes —
// run this first to learn the tenant's shape, then we wire the real detector.
// ?q=nurs.*assess &days=14 &max=6 — PHI-light output (client initials only).
app.get('/api/diag/kipu-cosign', requireAuth, requireAdmin, async (req, res) => {
  try {
    if (!kipuConfigured()) return res.status(400).json({ error: 'Kipu is not connected.' });
    const rx = new RegExp(req.query.q || 'nurs.*assess', 'i');
    const days = Math.min(Math.max(+req.query.days || 14, 1), 60);
    const maxScans = Math.min(Math.max(+req.query.max || 6, 1), 12);
    const since = addDays(appToday(), -days);
    const clients = db.prepare(`SELECT id, name, kipu_id, admit FROM clients WHERE merged_into IS NULL AND kipu_id IS NOT NULL AND (active = 1 OR substr(COALESCE(admit,''),1,10) >= ?) ORDER BY admit DESC LIMIT 40`).all(since);
    const out = [];
    let scanned = 0;
    for (const c of clients) {
      if (scanned >= maxScans) break;
      let evals = [];
      try { evals = await kipuFindEvalsByName(c.kipu_id, rx, since); } catch (e) { out.push({ client: nameInitials(c.name), error: 'list: ' + e.message.slice(0, 120) }); continue; }
      for (const ev of evals.slice(0, 2)) {
        if (scanned >= maxScans) break;
        scanned++;
        try {
          const scan = await kipuEvalSignatureScan(c.kipu_id, ev.id);
          out.push({ client: nameInitials(c.name), evalId: ev.id, name: ev.name, listStatus: ev.status, date: ev.date, detailStatus: scan.status, topKeys: scan.topKeys, signatureFields: scan.signatureFields });
        } catch (e) { out.push({ client: nameInitials(c.name), evalId: ev.id, name: ev.name, error: 'detail: ' + e.message.slice(0, 120) }); }
      }
    }
    res.json({ ok: true, pattern: String(rx), since, scanned, results: out });
  } catch (e) { res.status(502).json({ error: e.message }); }
});
app.get('/api/diag/admits', requireAuth, requireAdmin, (req, res) => {
  if (req.query.facility && !facilityAllowed(req.user, +req.query.facility)) return res.status(403).json({ error: 'No access to that facility.' });
  const today = appToday();
  const since = /^\d{4}-\d{2}-\d{2}$/.test(req.query.since || '') ? req.query.since : today.slice(0, 8) + '01';
  const end = /^\d{4}-\d{2}-\d{2}$/.test(req.query.end || '') ? req.query.end : today;
  const dfid = req.query.facility ? +req.query.facility : null;
  const DF = dfid ? ` AND facility_id=${dfid}` : '';
  const rows = db.prepare(`SELECT id, name, pref, kipu_id, admit, admit_time, discharge_date, discharge_status, source, active, referral_source FROM clients WHERE merged_into IS NULL AND admit IS NOT NULL AND substr(admit,1,10) >= ? AND substr(admit,1,10) <= ?${DF} ORDER BY admit, name`).all(since, end);
  // What the Corporate Command Center counts for this window (DISTINCT kipu_id+name):
  const ccCount = db.prepare(`SELECT COUNT(*) n FROM (SELECT DISTINCT kipu_id, name FROM clients WHERE merged_into IS NULL AND substr(admit,1,10) >= ? AND substr(admit,1,10) <= ?`+DF+`)`).get(since, end).n;
  const nameKey = (n) => String(n || '').toLowerCase().replace(/[^a-z ]/g, '').trim();
  const nameCount = {};
  rows.forEach((r) => { const k = nameKey(r.name); nameCount[k] = (nameCount[k] || 0) + 1; });
  const prior = db.prepare(`SELECT COUNT(*) n FROM clients WHERE merged_into IS NULL AND lower(name) = lower(?) AND admit IS NOT NULL AND substr(admit,1,10) < ?`);
  const admits = rows.map((r) => {
    const k = nameKey(r.name);
    const adm = String(r.admit).slice(0, 10);
    const readmit = prior.get(r.name, adm).n > 0;
    const sameDay = r.discharge_date && String(r.discharge_date).slice(0, 10) === adm;
    const flags = [
      readmit ? 'readmit' : null,
      nameCount[k] > 1 ? 'duplicate in window' : null,
      sameDay ? 'same-day discharge' : null,
      !r.kipu_id ? 'manual row (not from Kipu)' : null,
    ].filter(Boolean);
    return { name: r.name, admit: adm, time: r.admit_time || '', source: r.source || 'manual', discharged: r.discharge_date ? String(r.discharge_date).slice(0, 10) : '', status: r.discharge_status || '', referral: r.referral_source || '', flags };
  });
  res.json({
    since, end,
    total: admits.length,
    commandCenterCount: ccCount,
    distinctPeople: Object.keys(nameCount).length,
    readmits: admits.filter((a) => a.flags.includes('readmit')).length,
    sameDay: admits.filter((a) => a.flags.includes('same-day discharge')).length,
    manual: admits.filter((a) => a.flags.some((f) => f.startsWith('manual'))).length,
    admits,
  });
});

// ── Admit / Discharge diagnostic — read-only. Shows today's facility counts and the
// last few days of admits/discharges/scheduled with each one's STORED date + source,
// so a leader can see the off-by-a-day (or any miscount) directly. Changes nothing.
app.get('/api/diag/admit-discharge', requireAuth, requireAdmin, (req, res) => {
  const today = appToday();
  const win = addDays(today, -3);
  const fc = facCtx(req); if (denyFac(fc, res)) return;
  const census = db.prepare(`SELECT COUNT(*) n FROM clients WHERE active = 1 AND discharge_status IS NULL${fc.frag('facility_id')}`).get().n;
  const scheduledToday = db.prepare(`SELECT COUNT(*) n FROM expected_arrivals WHERE scheduled_date = ? AND status = 'expected'${fc.frag('facility_id')}`).get(today).n;
  const admittedToday = db.prepare(`SELECT COUNT(*) n FROM clients WHERE active = 1 AND discharge_status IS NULL AND substr(admit,1,10) = ?${fc.frag('facility_id')}`).get(today).n;
  const dischargedToday = db.prepare(`SELECT COUNT(*) n FROM clients WHERE substr(discharge_date,1,10) = ?${fc.frag('facility_id')}`).get(today).n;
  const admits = db.prepare(`SELECT pref, name, admit, admit_time, source, active, room FROM clients WHERE admit IS NOT NULL AND substr(admit,1,10) >= ?${fc.frag('facility_id')} ORDER BY admit DESC, admit_time DESC LIMIT 50`).all(win)
    .map((c) => ({ name: c.pref || c.name || '—', admit: (c.admit || '').slice(0, 10), time: c.admit_time || '', source: c.source || 'manual', active: !!c.active, room: c.room || '', isToday: (c.admit || '').slice(0, 10) === today }));
  const discharges = db.prepare(`SELECT pref, name, admit, discharge_date, discharge_status, discharge_reason, therapist, diagnosis, source FROM clients WHERE discharge_date IS NOT NULL AND substr(discharge_date,1,10) >= ?${fc.frag('facility_id')} ORDER BY discharge_date DESC LIMIT 50`).all(win)
    .map((c) => ({ name: c.pref || c.name || '—', date: (c.discharge_date || '').slice(0, 10), status: c.discharge_status || 'Discharged', source: c.source || 'manual', isToday: (c.discharge_date || '').slice(0, 10) === today, referredOut: isReferredOut(c) }));
  const scheduled = db.prepare(`SELECT preferred_name, first_name, last_name, scheduled_date, status FROM expected_arrivals WHERE scheduled_date >= ?${fc.frag('facility_id')} ORDER BY scheduled_date DESC LIMIT 50`).all(win)
    .map((s) => ({ name: s.preferred_name || [s.first_name, s.last_name].filter(Boolean).join(' ') || '—', date: s.scheduled_date || '', status: s.status || '', isToday: s.scheduled_date === today }));
  res.json({ today, facility: { census, scheduledToday, admittedToday, dischargedToday }, admits, discharges, scheduled });
});

// ── Merge duplicate patient records (admin) — review-then-confirm, reversible. ──
// Every table that references a client is reassigned to the kept record, blank
// fields are backfilled, and the duplicate is RETIRED (not deleted) with a JSON
// snapshot stored, so a merge can be reviewed or reversed.
function clientChildTables() {
  const tbls = db.prepare(`SELECT name FROM sqlite_master WHERE type='table' AND name NOT IN ('clients','client_merges','sqlite_sequence')`).all();
  const out = [];
  for (const t of tbls) { try { if (db.prepare(`PRAGMA table_info(${t.name})`).all().some((c) => c.name === 'client_id')) out.push(t.name); } catch {} }
  return out;
}
const dupNorm = (s) => String(s || '').toLowerCase().replace(/[^a-z ]/g, '').replace(/\s+/g, ' ').trim();
// Person-within-facility key (review fix): the same human at two facilities is
// two EPISODES — never one "duplicate" group. Rows selected for dup work must
// include facility_id or they fall into the shared 0-bucket.
const dupKeyOf = (c) => (((c.kipu_id ? String(c.kipu_id).split(':')[0] : '') || dupNorm(c.name)) + '|' + (c.facility_id || 0));
// Shared merge core (used by the manual tool AND the automatic de-dupe). Reassigns
// every client-linked table to the kept record, backfills only stable identity/
// clinical fields when blank (never discharge/location state), and RETIRES the
// duplicates (kept for reversibility via the client_merges snapshot). Transactional.
function mergeClients(keep, dupeIds, byName) {
  const keepRow = db.prepare(`SELECT * FROM clients WHERE id = ?`).get(keep);
  if (!keepRow) return { error: 'Keep record not found.' };
  const childTbls = clientChildTables();
  const fillFields = ['admit', 'admit_time', 'therapist', 'case_manager', 'diagnosis', 'allergies', 'medications', 'insurance', 'phone', 'dob', 'pronouns', 'language', 'mrn', 'payment_method', 'referral_source', 'kipu_id', 'photo'];
  let merged = 0;
  db.exec('BEGIN');
  try {
    for (const dupeId of dupeIds) {
      if (dupeId === keep) continue;
      const dupe = db.prepare(`SELECT * FROM clients WHERE id = ?`).get(dupeId);
      if (!dupe || dupe.merged_into) continue;
      db.prepare(`INSERT INTO client_merges (kept_id, dupe_id, snapshot, by_name) VALUES (?,?,?,?)`).run(keep, dupeId, JSON.stringify(dupe), byName);
      for (const t of childTbls) { try { db.prepare(`UPDATE ${t} SET client_id = ? WHERE client_id = ?`).run(keep, dupeId); } catch {} }
      for (const f of fillFields) { try { const kv = keepRow[f], dv = dupe[f]; if ((kv == null || String(kv).trim() === '') && dv != null && String(dv).trim() !== '') { db.prepare(`UPDATE clients SET ${f} = ? WHERE id = ?`).run(dv, keep); keepRow[f] = dv; } } catch {} }
      db.prepare(`UPDATE clients SET active = 0, merged_into = ?, discharge_status = 'Merged (duplicate)', discharge_date = NULL, anticipated_dc = NULL WHERE id = ?`).run(keep, dupeId);
      merged++;
    }
    db.exec('COMMIT');
  } catch (e) { try { db.exec('ROLLBACK'); } catch {} return { error: e.message }; }
  return { merged };
}
// A record is a CLEARLY-accidental shell (safe to auto-merge): no linked records,
// no real clinical data, and no real discharge write-up ("unable to determine / no
// documentation" doesn't count). Anything with substance is left for human review.
function isShellDuplicate(c, childCountFn) {
  if (childCountFn(c.id) > 0) return false;
  if ([c.therapist, c.diagnosis, c.allergies, c.medications, c.admit_time].some((x) => x && String(x).trim())) return false;
  const reason = String(c.discharge_reason || '').toLowerCase();
  if (reason && !/unable to determine|no documentation/.test(reason)) return false;
  return true;
}
// Automatic, conservative de-dupe — runs after each sync. ONLY collapses shell
// duplicates that share the SAME Kipu person id (master id); name-only matches and
// records with real data are never auto-merged (legitimate re-admission stays stay
// intact). Off via setState('auto_dedupe','off').
function autoMergeShellDuplicates() {
  if (getState('auto_dedupe') === 'off') return 0;
  const rows = db.prepare(`SELECT id, pref, name, kipu_id, facility_id, admit, admit_time, discharge_reason, therapist, diagnosis, allergies, medications, active FROM clients WHERE merged_into IS NULL AND kipu_id IS NOT NULL AND kipu_id != ''`).all();
  const childTbls = clientChildTables();
  const childCount = (id) => { let n = 0; for (const t of childTbls) { try { n += db.prepare(`SELECT COUNT(*) n FROM ${t} WHERE client_id = ?`).get(id).n; } catch {} } return n; };
  const groups = {};
  // Group by Kipu MASTER id AND facility — a person with episodes at two facilities
  // must NEVER be merged across them (Rebuild Phase 3: cross-facility collapse guard).
  for (const c of rows) { const k = String(c.kipu_id).split(':')[0]; if (!k) continue; const gk = k + '|' + (c.facility_id || 0); (groups[gk] = groups[gk] || []).push(c); }
  let total = 0;
  for (const k of Object.keys(groups)) {
    const g = groups[k]; if (g.length < 2) continue;
    const ranked = g.map((c) => ({ c, rich: childCount(c.id) + [c.admit, c.therapist, c.diagnosis, c.admit_time].filter((x) => x && String(x).trim()).length, active: c.active ? 1 : 0 }))
      .sort((a, b) => b.rich - a.rich || b.active - a.active || a.c.id - b.c.id);
    const keep = ranked[0].c;
    const shells = ranked.slice(1).map((x) => x.c).filter((c) => isShellDuplicate(c, childCount));
    if (!shells.length) continue;
    const r = mergeClients(keep.id, shells.map((s) => s.id), 'System (auto-dedupe)');
    if (r.merged) total += r.merged;
  }
  if (total) { try { audit({ user: { name: 'System (auto-dedupe)' }, action: 'CLIENT_MERGE_AUTO', detail: `${total} shell duplicate(s) merged`, ip: 'sync' }); } catch {} }
  return total;
}
// One-time historical cleanup of the census-churn phantoms. Groups by Kipu MASTER id
// (definitively the same person) and retires any row that has ZERO staff-created
// records — it was never a real cared-for stay, just a phantom created/discharged by
// the sync bug — into the row that DOES have the real activity. Rows with real linked
// records (rounds, notes, incidents…) are kept as genuine stays. Reversible.
function cleanupChurnDuplicates() {
  const rows = db.prepare(`SELECT id, pref, name, kipu_id, facility_id, admit, active FROM clients WHERE merged_into IS NULL AND kipu_id IS NOT NULL AND kipu_id != ''`).all();
  const childTbls = clientChildTables();
  const childCount = (id) => { let n = 0; for (const t of childTbls) { try { n += db.prepare(`SELECT COUNT(*) n FROM ${t} WHERE client_id = ?`).get(id).n; } catch {} } return n; };
  const groups = {};
  for (const c of rows) { const k = String(c.kipu_id).split(':')[0]; if (!k) continue; const gk = k + '|' + (c.facility_id || 0); (groups[gk] = groups[gk] || []).push(c); }
  let total = 0;
  for (const k of Object.keys(groups)) {
    const g = groups[k]; if (g.length < 2) continue;
    const withCounts = g.map((c) => ({ c, children: childCount(c.id), active: c.active ? 1 : 0 }));
    withCounts.sort((a, b) => b.children - a.children || b.active - a.active || a.c.id - b.c.id);
    const keep = withCounts[0].c;
    // Retire same-person rows that have NO staff-created records (never a real stay).
    const dups = withCounts.slice(1).filter((x) => x.children === 0).map((x) => x.c.id);
    if (!dups.length) continue;
    const r = mergeClients(keep.id, dups, 'System (churn cleanup)');
    if (r.merged) total += r.merged;
  }
  if (total) { try { audit({ user: { name: 'System (churn cleanup)' }, action: 'CLIENT_MERGE_CLEANUP', detail: `${total} phantom/duplicate record(s) retired`, ip: 'cleanup' }); } catch {} }
  return total;
}
// Retire PHANTOM DISCHARGES: a "discharged" row for a person who is CURRENTLY an
// active patient (they're still here) and whose discharge has no real outcome and no
// staff activity — a census-churn artifact. Documented prior stays (Completed/AMA/
// Transferred with a real reason, or any row with linked records) are kept. This fixes
// every discharge metric at the source, not query-by-query. Reversible.
function cleanupPhantomDischarges() {
  const norm = (s) => String(s || '').toLowerCase().replace(/[^a-z ]/g, '').replace(/\s+/g, ' ').trim();
  // Person AND facility: a discharge row at facility B is never a phantom of an
  // active stay at facility A (review fix — cross-facility guard).
  const keyOf = (c) => (((c.kipu_id ? String(c.kipu_id).split(':')[0] : '') || norm(c.name)) + '|' + (c.facility_id || 0));
  const childTbls = clientChildTables();
  const childCount = (id) => { let n = 0; for (const t of childTbls) { try { n += db.prepare(`SELECT COUNT(*) n FROM ${t} WHERE client_id = ?`).get(id).n; } catch {} } return n; };
  const activeByKey = {};
  for (const a of db.prepare(`SELECT id, kipu_id, name, facility_id FROM clients WHERE active = 1 AND discharge_status IS NULL AND merged_into IS NULL`).all()) { const k = keyOf(a); if (k && !activeByKey[k]) activeByKey[k] = a; }
  const disch = db.prepare(`SELECT id, kipu_id, name, facility_id, discharge_status, discharge_reason FROM clients WHERE merged_into IS NULL AND discharge_date IS NOT NULL`).all();
  let total = 0;
  for (const d of disch) {
    const k = keyOf(d); const act = activeByKey[k]; if (!act || act.id === d.id) continue;   // person not currently here → leave it
    const st = String(d.discharge_status || '').toLowerCase();
    const documented = /complete|\bama\b|against medical|transfer|graduat|detox complete|step/.test(st) && d.discharge_reason && !/unable to determine|no documentation/i.test(String(d.discharge_reason));
    if (documented) continue;            // a real, documented prior stay → keep
    if (childCount(d.id) > 0) continue;  // had real staff activity → keep for manual review
    const r = mergeClients(act.id, [d.id], 'System (phantom-discharge cleanup)');
    if (r.merged) total += r.merged;
  }
  if (total) { try { audit({ user: { name: 'System (phantom cleanup)' }, action: 'CLIENT_MERGE_PHANTOM', detail: `${total} phantom discharge(s) of active patients retired`, ip: 'cleanup' }); } catch {} }
  return total;
}
app.get('/api/diag/duplicates', requireAuth, requireAdmin, (req, res) => {
  const rows = db.prepare(`SELECT id, pref, name, kipu_id, facility_id, room, admit, admit_time, discharge_date, discharge_status, source, active, therapist, diagnosis FROM clients WHERE merged_into IS NULL ORDER BY name, id`).all();
  const groups = {};
  for (const c of rows) { const k = dupKeyOf(c); if (!k) continue; (groups[k] = groups[k] || []).push(c); }
  const childTbls = clientChildTables();
  const childCount = (id) => { let n = 0; for (const t of childTbls) { try { n += db.prepare(`SELECT COUNT(*) n FROM ${t} WHERE client_id = ?`).get(id).n; } catch {} } return n; };
  const out = [];
  for (const k of Object.keys(groups)) {
    const g = groups[k]; if (g.length < 2) continue;
    const items = g.map((c) => {
      const children = childCount(c.id);
      const fields = [c.admit, c.discharge_date, c.therapist, c.diagnosis, c.room].filter((x) => x && String(x).trim()).length;
      return { id: c.id, name: c.pref || c.name, kipu_id: c.kipu_id || '', room: c.room || '', admit: (c.admit || '').slice(0, 10), discharge_date: (c.discharge_date || '').slice(0, 10), discharge_status: c.discharge_status || '', source: c.source || 'manual', active: !!c.active, children, richness: fields + children };
    }).sort((a, b) => b.richness - a.richness || (b.active ? 1 : 0) - (a.active ? 1 : 0) || a.id - b.id);
    out.push({ key: k, name: items[0].name, rows: items, suggestKeep: items[0].id });
  }
  res.json({ groups: out, childTables: childTbls.length });
});
app.post('/api/diag/merge', requireAuth, requireAdmin, (req, res) => {
  const keep = +req.body?.keep;
  const dupes = Array.isArray(req.body?.dupes) ? [...new Set(req.body.dupes.map(Number))].filter((x) => x && x !== keep) : [];
  if (!keep || !dupes.length) return res.status(400).json({ error: 'Pick a record to keep and at least one duplicate to merge.' });
  // Review fix: never merge across facilities — an episode at another facility is
  // a different stay, not a duplicate (person-level linking is Phase 6's job).
  const keepFac = db.prepare(`SELECT facility_id FROM clients WHERE id=?`).get(keep)?.facility_id || 0;
  const crossFac = dupes.filter((d) => (db.prepare(`SELECT facility_id FROM clients WHERE id=?`).get(d)?.facility_id || 0) !== keepFac);
  if (crossFac.length) return res.status(400).json({ error: `Refusing to merge across facilities (rows ${crossFac.join(', ')} belong to a different facility). Same person at two facilities = two episodes, not a duplicate.` });
  const r = mergeClients(keep, dupes, req.user.name);
  if (r.error) return res.status(r.error === 'Keep record not found.' ? 404 : 500).json({ error: r.error });
  audit({ user: req.user, action: 'CLIENT_MERGE', detail: `kept ${keep}, merged ${r.merged} (${dupes.join(',')})`, ip: req.ip });
  res.json({ ok: true, merged: r.merged });
});
// Clean up everything — retire the census-churn phantom/duplicate records in one pass.
app.post('/api/diag/cleanup', requireAuth, requireAdmin, (req, res) => {
  let churn = 0, shells = 0, phantom = 0;
  try { churn = cleanupChurnDuplicates(); } catch (e) { return res.status(500).json({ error: e.message }); }
  try { phantom = cleanupPhantomDischarges(); } catch {}
  try { shells = autoMergeShellDuplicates(); } catch {}
  const merged = churn + phantom + shells;
  setState('churn_cleanup_last', `${new Date().toISOString().slice(0, 19).replace('T', ' ')} — ${merged} retired`);
  audit({ user: req.user, action: 'CLIENT_CLEANUP_RUN', detail: `${merged} retired (${churn} churn + ${phantom} phantom + ${shells} shells)`, ip: req.ip });
  res.json({ ok: true, merged, churn, phantom, shells });
});

/* ───────────── AKRON OUTPATIENT (owner-only, separate Kipu location) ───────────── */
const OUTPATIENT_DEFAULT_LOCATION = 'Akron House Recovery';
function outpatientLocationName() { return (getState('outpatient_location') || OUTPATIENT_DEFAULT_LOCATION).trim(); }
const opDays = (a, b) => { if (!a || !b) return null; const n = Math.round((Date.parse(String(b).slice(0, 10)) - Date.parse(String(a).slice(0, 10))) / 864e5); return Number.isFinite(n) && n >= 0 ? n : null; };
const avg1 = (arr) => arr.length ? +(arr.reduce((x, y) => x + y, 0) / arr.length).toFixed(1) : null;
app.get('/api/outpatient', requireAuth, requireOutpatient, (req, res) => {
  // Facility truth: an EXPLICIT chip pick shows ONLY that program's roster —
  // Spark with no sync yet reads 0, never a mirror of Akron's census. No pick
  // (All facilities / legacy staff) keeps today's full roster.
  let opPick = null;
  if (req.query.facility !== undefined && req.query.facility !== '') {
    const fid = +req.query.facility;
    if (!Number.isInteger(fid) || fid <= 0 || !facilityAllowed(req.user, fid)) return res.status(403).json({ error: 'No access to that facility.' });
    // Only an OUTPATIENT facility means anything here. A detox/housing pick (e.g.
    // a biller whose chip defaults to detox) falls back to the full roster rather
    // than a meaningless empty page claiming Kipu is down.
    const ftype = db.prepare(`SELECT type FROM org_facilities WHERE id=?`).get(fid)?.type;
    if (ftype === 'outpatient') opPick = fid;
  }
  const opFrag = opPick ? ` AND (facility_id = ${opPick}${opPick === outpatientFacilityId() ? ' OR facility_id IS NULL' : ''})` : '';
  const rows = db.prepare(`SELECT kipu_id, name, pref, level, loc_class, admit, mrn, therapist, payer FROM outpatient_clients WHERE active = 1${opFrag} ORDER BY loc_class, name`).all();
  const counts = { total: rows.length, PHP: 0, IOP: 0, OP: 0, Other: 0 };
  for (const r of rows) counts[r.loc_class] = (counts[r.loc_class] || 0) + 1;
  const access = req.user.role === 'admin'
    ? db.prepare(`SELECT id, name, username, job_role FROM users WHERE id IN (${outpatientAllowlist().map(() => '?').join(',') || 'NULL'})`).all(...outpatientAllowlist())
    : [];
  // Raw level-of-care text → count + how we classified it, so a 61-vs-40 mismatch is
  // diagnosable at a glance (e.g. everyone's level text reading the same value).
  const lb = {};
  for (const r of db.prepare(`SELECT level, loc_class, COUNT(*) n FROM outpatient_clients WHERE active = 1${opFrag} GROUP BY level, loc_class`).all()) {
    lb[(r.level || '(blank)') + '  →  ' + r.loc_class] = r.n;
  }
  // Connection + sync stamps are per facility: the default program reads the env
  // connection; any other facility reads ITS OWN 🔌 connection (none = not ready).
  const opFid = outpatientFacilityId();
  const scopedElsewhere = opPick && opPick !== opFid;
  const conn = scopedElsewhere ? resolveKipuConn(opPick) : null;
  res.json({
    location: scopedElsewhere ? (db.prepare(`SELECT kipu_location_name FROM org_facilities WHERE id=?`).get(opPick)?.kipu_location_name || '') : outpatientLocationName(),
    kipuReady: scopedElsewhere ? !!conn : kipuConfigured(),
    asOf: scopedElsewhere ? (getState('outpatient_synced_at_' + opPick) || null) : (getState('outpatient_synced_at') || null),
    counts,
    levelBreakdown: lb,
    roster: rows.map((r) => ({ name: r.pref || r.name, level: r.level, locClass: r.loc_class, admit: r.admit, therapist: r.therapist, mrn: r.mrn, payer: r.payer || '' })),
    isAdmin: req.user.role === 'admin',
    access: access.map((u) => ({ id: u.id, name: u.name, username: u.username, role: u.job_role || '' })),
    staff: req.user.role === 'admin' ? db.prepare(`SELECT id, name, job_role FROM users WHERE active=1 AND role!='admin' ORDER BY name`).all() : [],
  });
});
// Pull the outpatient census and update the history (admit = PHP start, detect
// PHP→IOP transition, mark drop-offs as discharged). Shared by the manual button
// AND the daily scheduler. Returns { error } or { location, counts }.
// Which registry facility owns the outpatient census (matches the location name).
function outpatientFacilityId() {
  const loc = outpatientLocationName().toLowerCase();
  const f = orgFacilities().find((x) => x.type === 'outpatient' && (x.kipu_location_name || '').toLowerCase() === loc)
        || orgFacilities().find((x) => x.type === 'outpatient' && (x.name || '').toLowerCase().includes(loc));
  return f ? f.id : null;
}
// Review fix: legacy outpatient rows predate facility_id — adopt them into the
// configured outpatient facility once (latched). They are NOT detox rows.
try {
  if (getState('phase3_outpatient_backfill') !== 'done') {
    const opf = outpatientFacilityId();
    if (opf) {
      db.prepare(`UPDATE outpatient_clients SET facility_id=? WHERE facility_id IS NULL`).run(opf);
      setState('phase3_outpatient_backfill', 'done');
    }
  }
} catch (e) { console.error('[phase3 outpatient backfill]', e.message); }
async function syncOutpatient(opts = {}) {
  // Per-facility mode (Spark etc.): its OWN connection + location, rows stamped
  // to that facility, matching and the discharge sweep FENCED to that facility —
  // a Spark sync can never touch Armada Clinical's roster (same guarantee
  // kipuSyncRoster gives the detox census).
  const fid = opts.facilityId ? +opts.facilityId : null;
  const conn = opts.conn || null;
  if (fid && !conn) return { error: 'This facility has no Kipu connection of its own.' };
  if (!fid && !kipuConfigured()) return { error: 'Kipu isn’t connected.' };
  const locName = fid ? (opts.locationName || '') : outpatientLocationName();
  let r; try { r = await kipuOutpatientCensus(locName, conn); } catch (e) { return { error: e.message }; }
  if (r.error) return { error: r.error };
  const today = appToday();
  const opFac = fid || outpatientFacilityId();
  // Match within THIS facility only (a second Kipu instance can reuse casefile
  // ids); the default program also owns its legacy NULL-stamped rows.
  const facMatch = fid ? `facility_id = ${fid}` : (opFac ? `(facility_id = ${opFac} OR facility_id IS NULL)` : `facility_id IS NULL`);
  const get = db.prepare(`SELECT kipu_id, iop_start, admit FROM outpatient_clients WHERE kipu_id = ? AND ${facMatch}`);
  const ins = db.prepare(`INSERT INTO outpatient_clients (kipu_id,name,pref,level,loc_class,admit,mrn,therapist,payer,php_start,iop_start,first_seen,last_seen,active,facility_id,updated_at)
    VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,1,${opFac || 'NULL'},datetime('now'))`);
  // Prefer the LATEST admission date Kipu has (the most recent stay), per the rule
  // "last admission date → first IOP date".
  const upd = db.prepare(`UPDATE outpatient_clients SET name=?,pref=?,level=?,loc_class=?,admit=COALESCE(NULLIF(?,''),admit),mrn=?,therapist=?,
    payer=COALESCE(NULLIF(payer,''),?),php_start=COALESCE(NULLIF(?,''),php_start),iop_start=?,last_seen=?,active=1,discharged_at=NULL,discharge_loc=NULL,facility_id=COALESCE(facility_id,${opFac || 'NULL'}),updated_at=datetime('now') WHERE kipu_id=? AND ${facMatch}`);
  const seen = new Set();
  db.exec('BEGIN');
  try {
    let i = 0;
    for (const p of r.patients) {
      const kid = p.kipuId || ('row' + (++i)); seen.add(kid);
      const ex = get.get(kid);
      // PHP→IOP step-down date comes straight from Kipu's program timeline now
      // (p.iopStart), so PHP length of stay is correct retroactively. Fall back to
      // forward-detection (first day we see them in IOP) only if Kipu has no history.
      const phpStart = p.phpStart || p.admit || today;
      if (!ex) {
        ins.run(kid, p.name, p.pref, p.level, p.loc_class, p.admit || null, p.mrn, p.therapist, p.payer, phpStart, p.iopStart || null, today, today);
      } else {
        let iopStart = p.iopStart || ex.iop_start;
        if (!iopStart && p.loc_class === 'IOP' && ex.admit) iopStart = today;   // just moved PHP→IOP, no history
        upd.run(p.name, p.pref, p.level, p.loc_class, p.admit || null, p.mrn, p.therapist, p.payer, p.phpStart || '', iopStart, today, kid);
      }
    }
    // Discharge sweep stays inside this facility's fence.
    const goneRows = db.prepare(`SELECT kipu_id, loc_class FROM outpatient_clients WHERE active = 1 AND ${facMatch}`).all();
    const setGone = db.prepare(`UPDATE outpatient_clients SET active=0, discharged_at=?, discharge_loc=? WHERE kipu_id=? AND ${facMatch}`);
    for (const g of goneRows) { if (!seen.has(g.kipu_id)) setGone.run(today, g.loc_class, g.kipu_id); }
    db.exec('COMMIT');
  } catch (e) { try { db.exec('ROLLBACK'); } catch { /* nothing to roll back */ } return { error: e.message }; }
  setState(fid ? 'outpatient_synced_at_' + fid : 'outpatient_synced_at', new Date().toISOString().slice(0, 19).replace('T', ' '));
  return { location: r.locationName, counts: r.counts, facilityId: opFac || null };
}
app.post('/api/outpatient/refresh', requireAuth, requireOutpatient, async (req, res) => {
  // Scoped to a non-default outpatient facility → refresh THAT program from its
  // own connection; otherwise the default program from the env credentials.
  const sc = outpatientScope(req, res); if (!sc) return;
  if (sc.fid && !sc.isDefault && !sc.conn) return res.status(503).json({ error: `${sc.fac.name} doesn’t have its own Kipu connection yet — finish the 🔌 setup on the Facilities page.` });
  const r = sc.fid && !sc.isDefault
    ? await syncOutpatient({ facilityId: sc.fid, locationName: sc.fac.kipu_location_name || '', conn: sc.conn })
    : await syncOutpatient();
  if (r.error) return res.status(/not found/i.test(r.error) ? 404 : 502).json({ error: r.error });
  audit({ user: req.user, action: 'OUTPATIENT_SYNC', detail: `${r.counts.total} at ${r.location} (PHP ${r.counts.PHP}, IOP ${r.counts.IOP})`, ip: req.ip });
  res.json({ ok: true, location: r.location, counts: r.counts });
});
// Live admit/discharge source. ONE Kipu pull (admissions over the last ~400 days)
// serves every dashboard window — we just re-filter the array in memory — so toggling
// 7d/30d/90d never triggers a fetch and can't flip the number. Cached 5 min, but the
// last good result is retained and served if a later fetch fails, so a transient Kipu
// hiccup never silently downgrades the count back to the census snapshot.
// Which outpatient facility is this request about? An explicit chip pick of a
// NON-default outpatient facility means: that program's data, through ITS OWN
// Kipu connection — never Akron's. Everything else keeps the legacy full view.
//   → { fid: null }            no/irrelevant pick — default program, env connection
//   → { fid, fac, conn }       scoped; conn null = its 🔌 isn't finished yet
//   → null                     forbidden/invalid (403 already sent)
function outpatientScope(req, res) {
  const q = req.query.facility;
  if (q === undefined || q === '') return { fid: null };
  const fid = +q;
  if (!Number.isInteger(fid) || fid <= 0 || !facilityAllowed(req.user, fid)) { res.status(403).json({ error: 'No access to that facility.' }); return null; }
  const fac = db.prepare(`SELECT id, name, type, kipu_location_name FROM org_facilities WHERE id=?`).get(fid);
  if (!fac || fac.type !== 'outpatient') return { fid: null };
  // The default program (Armada Clinical) scopes its DATA like everyone else but
  // keeps the shared env connection; it also owns legacy NULL-stamped rows.
  const isDefault = fid === outpatientFacilityId();
  return { fid, fac, isDefault, conn: resolveKipuConn(fid), frag: (col = 'facility_id') => ` AND (${col} = ${fid}${isDefault ? ` OR ${col} IS NULL` : ''})` };
}
let _opAdmAll = new Map();   // facility id (0 = default) → { day, at, data: [admissions] }
async function outpatientAllAdmissions(fid = 0, fac = null, conn = null) {
  const today = appToday();
  const hit = _opAdmAll.get(fid || 0);
  if (hit && hit.day === today && (Date.now() - hit.at) < 5 * 60 * 1000) return hit.data;
  if (fid ? !conn : !kipuConfigured()) return hit ? hit.data : null;
  const locName = fid ? (fac?.kipu_location_name || '') : outpatientLocationName();
  let r; try { r = await kipuOutpatientAdmissions(locName, addDays(today, -400), today, conn); } catch { return hit ? hit.data : null; }
  if (!r || r.error || !Array.isArray(r.admissions)) return hit ? hit.data : null;
  _opAdmAll.set(fid || 0, { day: today, at: Date.now(), data: r.admissions });
  return r.admissions;
}
// The diagnostic dashboard: admits/discharges over an adjustable period, census by
// level, LOS per level (+ trend), per-payer breakdown, and the "quick movers".
app.get('/api/outpatient/analytics', requireAuth, requireOutpatient, async (req, res) => {
  // Facility truth: a Spark pick reads SPARK's snapshot rows and SPARK's Kipu
  // admissions — never Akron's numbers wearing Spark's name.
  const sc = outpatientScope(req, res); if (!sc) return;
  const today = appToday();
  const since = /^\d{4}-\d{2}-\d{2}$/.test(req.query.since || '') ? req.query.since : addDays(today, -7);
  const end = /^\d{4}-\d{2}-\d{2}$/.test(req.query.end || '') ? req.query.end : today;
  const spanDays = Math.max(1, (opDays(since, end) || 0) + 1);
  const prevSince = addDays(since, -spanDays), prevEnd = addDays(since, -1);
  const inR = (d, s, e) => { const x = d ? String(d).slice(0, 10) : ''; return x && x >= s && x <= e; };
  const all = db.prepare(`SELECT * FROM outpatient_clients${sc.fid ? ` WHERE 1=1${sc.frag()}` : ''}`).all();
  const activeRows = all.filter((c) => c.active);
  const counts = { total: activeRows.length, PHP: 0, IOP: 0, OP: 0, Other: 0 };
  for (const c of activeRows) counts[c.loc_class] = (counts[c.loc_class] || 0) + 1;
  // Admits/discharges come from Kipu's admissions record (catches in-and-out people the
  // census snapshot never saw); fall back to the snapshot table if Kipu is unreachable.
  const liveAdm = sc.fid && !sc.isDefault
    ? await outpatientAllAdmissions(sc.fid, sc.fac, sc.conn)
    : await outpatientAllAdmissions(0, null, null);
  const levelByKid = new Map(all.map((c) => [String(c.kipu_id), c.loc_class]));
  let admits, discharges, admitRows, dischargeRows, source;
  if (liveAdm) {
    source = 'kipu-admissions';
    admitRows = liveAdm.filter((a) => inR(a.admit, since, end));
    admits = admitRows;
    dischargeRows = liveAdm.filter((a) => inR(a.discharge, since, end));
    discharges = dischargeRows;
  } else {
    source = 'snapshot';
    admitRows = all.filter((c) => inR(c.admit, since, end)).map((c) => ({ kipuId: String(c.kipu_id), name: c.pref || c.name, admit: c.admit, discharge: c.discharged_at, payer: c.payer }));
    admits = admitRows;
    dischargeRows = all.filter((c) => inR(c.discharged_at, since, end)).map((c) => ({ kipuId: String(c.kipu_id), name: c.pref || c.name, admit: c.admit, discharge: c.discharged_at, payer: c.payer }));
    discharges = dischargeRows;
  }
  const movedToIop = all.filter((c) => inR(c.iop_start, since, end));   // PHP→IOP this period
  // PHP LOS = admit→iop_start, for those who MOVED in the window (so it's period-bound & trendable)
  const phpLosWin = (s, e) => avg1(all.filter((c) => inR(c.iop_start, s, e) && c.admit).map((c) => opDays(c.admit, c.iop_start)).filter((n) => n != null));
  const iopLosWin = (s, e) => avg1(all.filter((c) => inR(c.discharged_at, s, e) && c.iop_start).map((c) => opDays(c.iop_start, c.discharged_at)).filter((n) => n != null));
  const avgPhpLos = phpLosWin(since, end), avgPhpPrev = phpLosWin(prevSince, prevEnd);
  const avgIopLos = iopLosWin(since, end), avgIopPrev = iopLosWin(prevSince, prevEnd);
  // current "days in level" for people still here (a live read, not completed LOS)
  const curPhpDays = avg1(activeRows.filter((c) => c.loc_class === 'PHP' && c.admit).map((c) => opDays(c.admit, today)).filter((n) => n != null));
  const curIopDays = avg1(activeRows.filter((c) => c.loc_class === 'IOP' && c.iop_start).map((c) => opDays(c.iop_start, today)).filter((n) => n != null));
  // per-payer
  const payers = {};
  const pk = (c) => (c.payer && c.payer.trim()) || 'Unknown';
  for (const c of activeRows) { const k = pk(c); (payers[k] = payers[k] || { payer: k, php: 0, iop: 0, total: 0, phpLos: [], iopLos: [] }); payers[k].total++; if (c.loc_class === 'PHP') payers[k].php++; else if (c.loc_class === 'IOP') payers[k].iop++; }
  for (const c of all) { const k = pk(c); payers[k] = payers[k] || { payer: k, php: 0, iop: 0, total: 0, phpLos: [], iopLos: [] }; const pd = (c.iop_start && c.admit) ? opDays(c.admit, c.iop_start) : null; if (pd != null) payers[k].phpLos.push(pd); const id = (c.iop_start && c.discharged_at) ? opDays(c.iop_start, c.discharged_at) : null; if (id != null) payers[k].iopLos.push(id); }
  const payerList = Object.values(payers).map((p) => ({ payer: p.payer, php: p.php, iop: p.iop, total: p.total, avgPhpLos: avg1(p.phpLos), avgIopLos: avg1(p.iopLos) })).sort((a, b) => b.total - a.total);
  // quick movers — moved PHP→IOP unusually fast (short PHP authorization)
  const quickThresh = +(getState('outpatient_quick_days') || 7);
  const quick = all.map((c) => { const pd = (c.iop_start && c.admit) ? opDays(c.admit, c.iop_start) : null; return pd != null && pd <= quickThresh ? { name: c.pref || c.name, payer: c.payer || '', phpDays: pd, admit: (c.admit || '').slice(0, 10), iopStart: (c.iop_start || '').slice(0, 10), active: !!c.active } : null; }).filter(Boolean).sort((a, b) => a.phpDays - b.phpDays);
  const tracking = !!getState(sc.fid && !sc.isDefault ? 'outpatient_synced_at_' + sc.fid : 'outpatient_synced_at');
  // The exact admits we counted — so a real-vs-app gap can be diagnosed by name.
  // active = still enrolled (no discharge date on the admissions record).
  const admitList = admitRows.map((a) => ({ name: a.pref || a.name, admit: (a.admit || '').slice(0, 10), discharged: (a.discharge || '').slice(0, 10), level: levelByKid.get(String(a.kipuId)) || '', active: !(a.discharge && String(a.discharge).slice(0, 10)), sameDay: a.admit && a.discharge && String(a.admit).slice(0, 10) === String(a.discharge).slice(0, 10) }))
    .sort((a, b) => (a.admit < b.admit ? 1 : a.admit > b.admit ? -1 : 0));
  const admitsStillHere = admitList.filter((a) => a.active).length;
  // The exact discharges in the window, with length of stay (admit→discharge).
  const dischargeList = dischargeRows.map((a) => {
    const admit = (a.admit || '').slice(0, 10), disch = (a.discharge || '').slice(0, 10);
    const los = (admit && disch) ? opDays(admit, disch) : null;
    return { name: a.pref || a.name, admit, discharged: disch, level: levelByKid.get(String(a.kipuId)) || '', los, sameDay: admit && disch && admit === disch };
  }).sort((a, b) => (a.discharged < b.discharged ? 1 : a.discharged > b.discharged ? -1 : 0));
  const admitsPrev = liveAdm ? liveAdm.filter((a) => inR(a.admit, prevSince, prevEnd)).length : null;
  res.json({
    since, end, spanDays, perWeek: +(admits.length / (spanDays / 7)).toFixed(1),
    counts,
    admits: admits.length, discharges: discharges.length, movedToIop: movedToIop.length,
    admitsPrev, admitList, admitsStillHere, dischargeList, source,
    los: { php: avgPhpLos, phpPrev: avgPhpPrev, iop: avgIopLos, iopPrev: avgIopPrev, curPhpDays, curIopDays },
    payers: payerList,
    quick, quickThresh,
    tracking,
  });
});
// PHP completion: of everyone admitted in the window, how many discharged WITHOUT
// ever reaching IOP (didn't complete PHP) — split into "right away" (≤1 day, usually
// a referral-out) and "left during PHP" (≥2 days but before the IOP step-down).
// Defaults to the current calendar month. Cached 5 min (it fetches program history
// per admit). Retains last good result so a Kipu hiccup doesn't blank it.
let _phpOutCache = new Map();   // key `${since}|${end}` → { at, data }
app.get('/api/outpatient/php-outcomes', requireAuth, requireOutpatient, async (req, res) => {
  // Facility truth: this panel reads live program history, so a scoped facility
  // needs ITS OWN Kipu connection — an honest "not connected yet" beats Akron's
  // numbers under Spark's name.
  const sc = outpatientScope(req, res); if (!sc) return;
  if (sc.fid && !sc.isDefault && !sc.conn) return res.status(503).json({ error: `${sc.fac.name} doesn’t have its own Kipu connection yet — finish the 🔌 setup on the Facilities page and this panel comes alive.` });
  if ((!sc.fid || sc.isDefault) && !kipuConfigured()) return res.status(503).json({ error: 'Kipu isn’t connected.' });
  const today = appToday();
  const since = /^\d{4}-\d{2}-\d{2}$/.test(req.query.since || '') ? req.query.since : today.slice(0, 8) + '01';
  const end = /^\d{4}-\d{2}-\d{2}$/.test(req.query.end || '') ? req.query.end : today;
  const key = `${sc.fid && !sc.isDefault ? sc.fid : 0}|${since}|${end}`;
  const hit = _phpOutCache.get(key);
  let r;
  if (hit && (Date.now() - hit.at) < 5 * 60 * 1000) r = hit.data;
  else {
    try { r = await kipuOutpatientPhpOutcomes(sc.fid && !sc.isDefault ? (sc.fac.kipu_location_name || '') : outpatientLocationName(), since, end, sc.fid && !sc.isDefault ? sc.conn : null); } catch (e) { r = hit ? hit.data : { error: e.message }; }
    if (r && !r.error) _phpOutCache.set(key, { at: Date.now(), data: r });
    else if (hit) r = hit.data;
  }
  if (!r || r.error) return res.status(502).json({ error: (r && r.error) || 'Could not read PHP outcomes.' });
  const losOf = (a, d) => (a && d) ? opDays(String(a).slice(0, 10), String(d).slice(0, 10)) : null;
  const people = (r.people || []).map((p) => ({ ...p, los: losOf(p.admit, p.discharge) }));
  const admitted = people.length;
  const reachedIop = people.filter((p) => p.hasIop).length;
  const stillIn = people.filter((p) => !p.discharged && !p.hasIop).length;
  // Didn't complete PHP = discharged and never reached IOP.
  const nonComplete = people.filter((p) => p.discharged && !p.hasIop);
  const rightAwayDays = +(getState('outpatient_rightaway_days') || 3);
  const isRightAway = (p) => p.los != null && p.los <= rightAwayDays;
  const rightAway = nonComplete.filter(isRightAway);
  const leftDuringPhp = nonComplete.filter((p) => !isRightAway(p));
  const list = nonComplete.map((p) => ({ name: p.name, payer: p.payer || '', admit: (p.admit || '').slice(0, 10), discharged: (p.discharge || '').slice(0, 10), los: p.los, bucket: isRightAway(p) ? 'right away' : 'left during PHP' }))
    .sort((a, b) => ((a.los ?? 99) - (b.los ?? 99)));
  res.json({
    since: r.since, end: r.end, admitted, reachedIop, stillIn, rightAwayDays,
    didNotCompletePhp: nonComplete.length, rightAway: rightAway.length, leftDuringPhp: leftDuringPhp.length,
    completionRate: (reachedIop + nonComplete.length) ? Math.round((reachedIop / (reachedIop + nonComplete.length)) * 100) : null,
    list,
  });
});
// Discovery: list every location in the connected Kipu account, so we can see which
