// ── Consolidated OWNERSHIP view across all facilities ──────────────────────────
// One call per outpatient location (admissions over a 400-day lookback), cached, so
// current census + admits/discharges for the window come from a single fast pull.
// Detox comes from the local clients table. Spark facilities show "pending" until
// their Kipu connection is added.
const _facAdmCache = new Map();   // locationName(lower) → { at, data:[admissions] }
async function facilityAdmissions(locName) {
  const key = String(locName || '').toLowerCase();
  const hit = _facAdmCache.get(key);
  if (hit && (Date.now() - hit.at) < 5 * 60 * 1000) return hit.data;
  if (!kipuConfigured()) return hit ? hit.data : null;
  let r; try { r = await kipuOutpatientAdmissions(locName, addDays(appToday(), -400), appToday()); } catch { return hit ? hit.data : null; }
  if (!r || r.error || !Array.isArray(r.admissions)) return hit ? hit.data : null;
  _facAdmCache.set(key, { at: Date.now(), data: r.admissions });
  return r.admissions;
}
let _locBedsCache = null;
async function locationBeds() {
  if (_locBedsCache && (Date.now() - _locBedsCache.at) < 30 * 60 * 1000) return _locBedsCache.map;
  const map = {};
  if (kipuConfigured()) { try { const r = await kipuListLocations(); for (const l of (r.locations || [])) if (l.beds != null) map[l.name.toLowerCase()] = l.beds; } catch { /* best-effort */ } }
  _locBedsCache = { at: Date.now(), map };
  return map;
}
app.get('/api/ownership', requireAuth, requireOutpatient, async (req, res) => {
  const today = appToday();
  const since = /^\d{4}-\d{2}-\d{2}$/.test(req.query.since || '') ? req.query.since : addDays(today, -7);
  const end = /^\d{4}-\d{2}-\d{2}$/.test(req.query.end || '') ? req.query.end : today;
  const inR = (d, s, e) => { const x = d ? String(d).slice(0, 10) : ''; return x && x >= s && x <= e; };
  const facilities = getFacilities();
  const beds = await locationBeds();
  const out = [];
  for (const f of facilities) {
    const base = { key: f.key, label: f.label, brand: f.brand, connection: f.connection, type: f.type, locationName: f.locationName };
    if (!connectionReachable(f.connection)) { out.push({ ...base, pending: true, note: f.connection === 'spark' ? 'Connect Spark Kipu to include' : 'Kipu not connected' }); continue; }
    if (f.type === 'detox') {
      const census = db.prepare(`SELECT COUNT(*) n FROM clients WHERE active = 1 AND discharge_status IS NULL AND merged_into IS NULL`).get().n;
      const admitRows = db.prepare(`SELECT DISTINCT kipu_id, name FROM clients WHERE merged_into IS NULL AND substr(admit,1,10) >= ? AND substr(admit,1,10) <= ?`).all(since, end);
      out.push({ ...base, census: { total: census }, admits: admitRows.length, discharges: realDischargeCount(since, end), beds: beds[(f.locationName || '').toLowerCase()] || null });
    } else {
      const adm = await facilityAdmissions(f.locationName);
      if (!adm) { out.push({ ...base, pending: true, note: 'No data from Kipu — check the location name' }); continue; }
      const census = adm.filter((a) => !a.discharge).length;
      out.push({ ...base, census: { total: census }, admits: adm.filter((a) => inR(a.admit, since, end)).length, discharges: adm.filter((a) => inR(a.discharge, since, end)).length, beds: beds[(f.locationName || '').toLowerCase()] || null });
    }
  }
  const live = out.filter((f) => !f.pending);
  const sum = (k) => live.reduce((a, f) => a + (k === 'census' ? (f.census?.total || 0) : (f[k] || 0)), 0);
  const byBrand = {};
  for (const f of live) { const b = byBrand[f.brand] = byBrand[f.brand] || { brand: f.brand, census: 0, admits: 0, discharges: 0 }; b.census += f.census?.total || 0; b.admits += f.admits || 0; b.discharges += f.discharges || 0; }
  res.json({
    window: { since, end },
    facilities: out,
    totals: { census: sum('census'), admits: sum('admits'), discharges: sum('discharges'), facilities: live.length },
    byBrand: Object.values(byBrand),
    sparkPending: facilities.some((f) => f.connection === 'spark') && !sparkConfigured(),
  });
});
// ── Corporate Operations Hub (Chava) ──────────────────────────────────────────
// One dashboard: ordering + maintenance status with completion counts and cycle
// times, the project board, vendors, and the facility document store.
function cycleDays(a, b) { if (!a || !b) return null; const n = (Date.parse(b) - Date.parse(a)) / 864e5; return n >= 0 ? +n.toFixed(1) : null; }
function avgOf(arr) { const v = arr.filter((n) => n != null); return v.length ? +(v.reduce((a, b) => a + b, 0) / v.length).toFixed(1) : null; }
app.get('/api/corp/overview', requireAuth, requireCorp, (req, res) => {
  const since = /^\d{4}-\d{2}-\d{2}$/.test(req.query.since || '') ? req.query.since : addDays(appToday(), -30);
  // Optional facility scope — the dashboard's facility switcher. '' = all locations.
  const facility = orgLocations().includes(req.query.facility) ? req.query.facility : '';
  const facSql = facility ? ` AND facility = ?` : '';
  const fa = facility ? [facility] : [];
  // Ordering from the unified order_requests stream (all locations, facility-scopable).
  const ordDone = db.prepare(`SELECT created_at, ordered_at, received_at FROM order_requests WHERE status='received' AND substr(received_at,1,10) >= ?${facSql}`).all(since, ...fa);
  const ordering = {
    open: db.prepare(`SELECT COUNT(*) n FROM order_requests WHERE status IN ('requested','ordered')${facSql}`).get(...fa).n,
    awaitingOrder: db.prepare(`SELECT COUNT(*) n FROM order_requests WHERE status='requested'${facSql}`).get(...fa).n,
    ordered: db.prepare(`SELECT COUNT(*) n FROM order_requests WHERE status='ordered'${facSql}`).get(...fa).n,
    completed: ordDone.length,
    avgToOrderDays: avgOf(ordDone.map((r) => cycleDays(r.created_at, r.ordered_at))),
    avgToReceiveDays: avgOf(ordDone.map((r) => cycleDays(r.ordered_at || r.created_at, r.received_at))),
  };
  // Maintenance: open, in progress, resolved in window, cycle time (facility-scopable).
  const mDone = db.prepare(`SELECT created_at, resolved_at FROM maintenance_requests WHERE status IN ('resolved','closed') AND substr(resolved_at,1,10) >= ?${facSql}`).all(since, ...fa);
  const maintenance = {
    open: db.prepare(`SELECT COUNT(*) n FROM maintenance_requests WHERE status='open'${facSql}`).get(...fa).n,
    inProgress: db.prepare(`SELECT COUNT(*) n FROM maintenance_requests WHERE status='in_progress'${facSql}`).get(...fa).n,
    openTotal: db.prepare(`SELECT COUNT(*) n FROM maintenance_requests WHERE status IN ('open','in_progress')${facSql}`).get(...fa).n,
    completed: mDone.length,
    avgResolveDays: avgOf(mDone.map((r) => cycleDays(r.created_at, r.resolved_at))),
  };
  // Project board rollup (facility-scopable).
  const tasks = db.prepare(`SELECT status, COUNT(*) n FROM corp_tasks WHERE 1=1${facSql} GROUP BY status`).all(...fa);
  const taskCounts = { todo: 0, doing: 0, blocked: 0, done: 0 };
  for (const t of tasks) taskCounts[t.status] = t.n;
  // Where things are being requested right now (only meaningful in the all-locations view).
  const openOrders = db.prepare(`SELECT facility, status, COUNT(*) n FROM order_requests WHERE status IN ('requested','ordered') GROUP BY facility, status`).all();
  const ordersByLocation = {};
  for (const r of openOrders) { const l = ordersByLocation[r.facility] = ordersByLocation[r.facility] || { facility: r.facility, requested: 0, ordered: 0 }; l[r.status] = r.n; }
  ordering.byLocation = Object.values(ordersByLocation).sort((a, b) => (b.requested + b.ordered) - (a.requested + a.ordered));
  ordering.locationsRequesting = ordering.byLocation.length;
  // The actual to-order list so it pops on the dashboard and she can act right away.
  ordering.toOrder = db.prepare(`SELECT id, facility, item_name, qty, category, vendor, link, priority FROM order_requests WHERE status='requested'${facSql} ORDER BY CASE priority WHEN 'Urgent' THEN 0 WHEN 'High' THEN 1 WHEN 'Normal' THEN 2 ELSE 3 END, id DESC LIMIT 40`).all(...fa);
  res.json({ since, facility, locations: orgLocations(), ordering, maintenance, taskCounts });
});
