// One-time bulk import from the entity information sheet (owner uploads the JSON I
// prepared). Replaces existing rows so re-import is idempotent.
// Shared import (JSON payload or a parsed workbook) — replaces existing vault data.
function importEntityVault(b) {
  const s = (v, n) => String(v == null ? '' : v).slice(0, n);
  let n = { records: 0, banks: 0, cards: 0, portals: 0 };
  db.exec('BEGIN');
  try {
    if (Array.isArray(b.records)) {
      db.exec('DELETE FROM entity_records');
      const ins = db.prepare(`INSERT INTO entity_records (entity,legal_name,tax_id,npi,taxonomy,medicaid_id,duns,address,mailing_address,incorp_date,notes,status) VALUES (?,?,?,?,?,?,?,?,?,?,?,?)`);
      for (const r of b.records) { ins.run(s(r.entity, 120), s(r.legal_name, 160), s(r.tax_id, 40), s(r.npi, 60), s(r.taxonomy, 60), s(r.medicaid_id, 120), s(r.duns, 40), s(r.address, 300), s(r.mailing_address, 300), s(r.incorp_date, 40), s(r.notes, 2000), r.status === 'closed' ? 'closed' : 'active'); n.records++; }
    }
    if (Array.isArray(b.banks)) {
      db.exec('DELETE FROM entity_bank_accounts');
      const ins = db.prepare(`INSERT INTO entity_bank_accounts (entity,bank,routing,account_number,acct_type,notes) VALUES (?,?,?,?,?,?)`);
      for (const r of b.banks) { ins.run(s(r.entity, 120), s(r.bank, 80), s(r.routing, 40), s(r.account_number, 60), s(r.acct_type, 40), s(r.notes, 500)); n.banks++; }
    }
    if (Array.isArray(b.cards)) {
      db.exec('DELETE FROM entity_cards');
      const ins = db.prepare(`INSERT INTO entity_cards (entity,name_on_card,card_number,exp,front_code,back_code,notes) VALUES (?,?,?,?,?,?,?)`);
      for (const r of b.cards) { ins.run(s(r.entity, 120), s(r.name_on_card, 80), s(r.card_number, 40), s(r.exp, 10), s(r.front_code, 10), s(r.back_code, 10), s(r.notes, 500)); n.cards++; }
    }
    if (Array.isArray(b.portals)) {
      db.exec('DELETE FROM portals');
      const ins = db.prepare(`INSERT INTO portals (name,username,password,info,entity) VALUES (?,?,?,?,?)`);
      for (const r of b.portals) { ins.run(s(r.name, 120), s(r.username, 120), s(r.password, 120), s(r.info, 1000), s(r.entity, 120)); n.portals++; }
    }
    db.exec('COMMIT');
  } catch (e) { try { db.exec('ROLLBACK'); } catch { /* ignore */ } throw e; }
  return n;
}
app.post('/api/corp/entities/import', requireAuth, requireAdmin, (req, res) => {
  try { res.json({ ok: true, imported: importEntityVault(req.body || {}) }); }
  catch (e) { res.status(500).json({ error: e.message }); }
});
// Upload the ORIGINAL Entity Information .xlsx — the app parses it directly
// (entities, banks, cards, portals) so there's no JSON middle step.
app.post('/api/corp/entities/import-xlsx', requireAuth, requireAdmin, (req, res) => {
  const data = String(req.body?.data || '').replace(/^data:[^;]+;base64,/, '');
  if (!data) return res.status(400).json({ error: 'No file received.' });
  let parsed;
  try { parsed = parseEntityWorkbook(Buffer.from(data, 'base64')); }
  catch (e) { return res.status(400).json({ error: 'Could not read that Excel file: ' + e.message }); }
  if (!parsed.records.length) return res.status(400).json({ error: 'No entities found — is this the Entity Information sheet?' });
  try { res.json({ ok: true, imported: importEntityVault(parsed) }); }
  catch (e) { res.status(500).json({ error: e.message }); }
});
// ── HR / Ownership employee roster (admin-only — salary is sensitive) ──────────
// Everyone across every entity, broken down by location, with job title + salary.
app.get('/api/hr/employees', requireAuth, requireAdmin, (req, res) => {
  const rows = db.prepare(`SELECT * FROM hr_employees WHERE status='active' ORDER BY entity, last_name, first_name`).all();
  const byEntity = {};
  for (const r of rows) {
    const e = byEntity[r.entity] = byEntity[r.entity] || { entity: r.entity, count: 0, annual: 0, withSalary: 0, people: [] };
    e.count++; e.people.push(r);
    if (r.salary != null && r.salary > 0) { e.withSalary++; e.annual += r.pay_type === 'hourly' ? r.salary * 2080 : r.salary; }
  }
  const groups = Object.values(byEntity).sort((a, b) => b.count - a.count);
  const totalAnnual = groups.reduce((a, g) => a + g.annual, 0);
  res.json({ groups, totals: { headcount: rows.length, annual: totalAnnual, withSalary: rows.filter((r) => r.salary > 0).length } });
});
