app.post('/api/employee/:id/coach', requireAuth, async (req, res) => {
  if (!canSeeTeamStats(req.user)) return res.status(403).json({ error: 'Leadership only.' });
  if (!claudeConfigured()) return res.status(503).json({ error: 'AI is not configured.' });
  const u = db.prepare(`SELECT id, name, job_role FROM users WHERE id=?`).get(+req.params.id);
  if (!u) return res.status(404).json({ error: 'Not found' });
  const s = userStats(u); const prev = prevOverall(u); const p = empProfile(u.id);
  const strong = s.required.filter((r) => r.pct != null && r.pct >= 90).map((r) => r.label);
  const improve = s.required.filter((r) => r.pct != null && r.pct < 70).map((r) => r.label);
  const wows90 = db.prepare(`SELECT COUNT(*) n FROM wows WHERE recognize=? AND created_at>=datetime('now','-90 day')`).get(u.name).n;
  const log = db.prepare(`SELECT note FROM employee_notes WHERE user_id=? ORDER BY id DESC LIMIT 10`).all(u.id).map((n) => n.note);
  const disc = empDisc(u.id); const b5 = empBig5(u.id); const sjt = empSjt(u.id);
  const ctx = [
    `Employee: ${u.name} — ${u.job_role || 'staff'}`,
    disc ? `Personality (DISC): ${DISC_GUIDE[disc.primary].name} primary / ${DISC_GUIDE[disc.secondary].name} secondary. They appreciate: ${DISC_GUIDE[disc.primary].appreciate}` : '',
    b5 ? `Big Five + Honesty-Humility (0-100, forced-choice so it can't be gamed): Conscientiousness ${b5.C}, Emotional stability ${b5.ES}, Warmth ${b5.A}, Extraversion ${b5.E}, Openness ${b5.O}, Honesty-Humility ${b5.H}. Higher = stronger.` : '',
    sjt ? `Situational judgment (0-100, real on-the-job scenarios): Integrity ${sjt.integrity}, De-escalation ${sjt.deescalation}, Reliability ${sjt.reliability}, Care & warmth ${sjt.care}. Treat low scores as development areas, never as a verdict on the person.` : '',
    `Overall performance this week: ${s.overall != null ? s.overall + '%' : 'n/a'} (trend ${prev != null && s.overall != null ? (s.overall - prev >= 0 ? '+' : '') + (s.overall - prev) : 'n/a'} vs last week)`,
    `Excelling at: ${strong.join(', ') || '—'}`,
    `Needs development: ${improve.join(', ') || '—'}`,
    `Recognition received (90d): ${wows90} Wows`,
    p.likes ? `What they like: ${p.likes}` : '',
    p.personality ? `Personality & style: ${p.personality}` : '',
    p.motivators ? `What motivates them: ${p.motivators}` : '',
    p.recognition ? `How they like recognition: ${p.recognition}` : '',
    p.notes ? `Notes: ${p.notes}` : '',
    log.length ? `Recent coaching log: ${log.join(' | ')}` : '',
  ].filter(Boolean).join('\n');
  const q = `You are Horst Schulze, Ritz-Carlton co-founder, coaching the OWNER on how to lead ONE employee at an addiction-treatment center. We treat our people the way we ask them to treat clients: dignity, genuine care, and high standards. Give concise, warm, specific guidance in three short labeled parts:\n1) RECOGNIZE — how to encourage and recognize this person this week, tailored to them.\n2) DEVELOP — where to help them grow and how to coach it with care (never punishment), focusing on any "needs development" areas.\n3) ONE MOVE — a single concrete thing to do this week to make them feel valued and raise their game.\nBe direct, human, and practical. Do not invent facts beyond the data provided.`;
  try { const brief = await askAssistant(q, ctx); res.json({ brief }); }
  catch (e) { res.status(502).json({ error: e.message }); }
});

/* ───────────── LEADERSHIP MIRROR — the executive-coach read ─────────────
   The highest-level assessment, for the CEO and every leader. Three layers a
   top consultant would insist on: (1) REAL DATA — what's actually happening in
   the org they lead; (2) a hard-to-game leadership STYLE read (forced-choice);
   (3) leadership JUDGMENT on real executive dilemmas. Then Horst gives an
   honest read of where they strive, where they struggle, and how they best
   lead. For development — honest, never punitive. */
const LEAD_COMPS = {
  vision: 'Vision & standards', develop: 'Develops people', accountability: 'Accountability & follow-through',
  composure: 'Composure under pressure', integrity: 'Integrity', decisiveness: 'Decisiveness', listening: 'Listening & empathy',
};
// Forced-choice style blocks — every option is a real leadership strength, so you
// can't ace it by picking the "good" answer. Pick MOST and LEAST like you.
const LEAD_FC = [
  [{ k: 'vision', t: 'I hold an uncompromising standard, even when it’s costly' }, { k: 'develop', t: 'I spend real time growing my people' }, { k: 'decisiveness', t: 'I make the call when others hesitate' }, { k: 'listening', t: 'I truly hear people before I respond' }],
  [{ k: 'accountability', t: 'I close every loop I open' }, { k: 'composure', t: 'I’m steadiest when it’s chaos' }, { k: 'integrity', t: 'I do the right thing when no one would know' }, { k: 'vision', t: 'I keep everyone pointed at the bigger why' }],
  [{ k: 'develop', t: 'I catch people doing it right and say so' }, { k: 'listening', t: 'I ask more than I tell' }, { k: 'decisiveness', t: 'I’d rather decide and adjust than wait' }, { k: 'accountability', t: 'I own the miss before I look outward' }],
  [{ k: 'integrity', t: 'I’d hold a top performer to the same line as everyone' }, { k: 'composure', t: 'Bad news doesn’t rattle me' }, { k: 'vision', t: 'I set the bar higher than people think possible' }, { k: 'develop', t: 'I build leaders, not just followers' }],
  [{ k: 'listening', t: 'People tell me the hard truth because I make it safe' }, { k: 'accountability', t: 'My commitments are as good as done' }, { k: 'decisiveness', t: 'I cut through analysis to a clear next step' }, { k: 'integrity', t: 'My word and my actions match' }],
  [{ k: 'composure', t: 'I keep the room calm in a crisis' }, { k: 'vision', t: 'I can paint the future so people want it' }, { k: 'develop', t: 'I’d give up a win to grow someone' }, { k: 'listening', t: 'I read what people aren’t saying' }],
  [{ k: 'decisiveness', t: 'I take responsibility for the tough decisions' }, { k: 'integrity', t: 'I admit my mistakes out loud' }, { k: 'accountability', t: 'I follow through on the unglamorous things' }, { k: 'composure', t: 'Pressure makes me more focused, not less' }],
];
// Leadership judgment — real executive dilemmas where every choice is defensible.
// The trade-offs (loyalty vs. fairness, speed vs. buy-in, candor vs. morale) make
// the best answer subtle, not obvious. Best=2, reasonable=1, off=0.
const LEAD_SJT = [
  { c: 'integrity', s: 'Your best, hardest-to-replace employee broke a cash-handling rule. No client was harmed and they feel terrible.', o: [
    { t: 'Same standard as anyone — address it directly, with care and a clear path forward', v: 2 },
    { t: 'Handle it quietly and privately so you don’t risk losing them', v: 1 },
    { t: 'Note it and watch closely for a pattern before acting', v: 0 },
    { t: 'Have the whole team re-trained so no one feels singled out', v: 1 } ] },
  { c: 'develop', s: 'A leader who reports to you keeps missing the mark. They’re well-liked and trying hard.', o: [
    { t: 'Coach them directly with a clear plan, support, and a follow-up date', v: 2 },
    { t: 'Have a frank talk and set a firm deadline with consequences', v: 1 },
    { t: 'Lighten their load and give them more support for now', v: 1 },
    { t: 'Quietly pick up the slack yourself so the team doesn’t suffer', v: 0 } ] },
  { c: 'accountability', s: 'An initiative you personally championed failed and it cost real money.', o: [
    { t: 'Own it openly, name the lesson, and fix the process', v: 2 },
    { t: 'Acknowledge it to your team privately and quietly course-correct', v: 1 },
    { t: 'Frame it as a calculated bet that didn’t land', v: 0 },
    { t: 'Move fast to the next thing so it’s not dwelt on', v: 0 } ] },
  { c: 'composure', s: 'Two emergencies hit at once and your rattled team is looking to you.', o: [
    { t: 'Get visibly calm, name the top priority, and assign clear next steps', v: 2 },
    { t: 'Jump in and personally handle the biggest fire yourself', v: 1 },
    { t: 'Pull your most capable person and tackle them together', v: 1 },
    { t: 'Match their urgency so they know you take it seriously', v: 0 } ] },
  { c: 'listening', s: 'A frontline tech tells you, in front of others, that a policy you set is hurting clients.', o: [
    { t: 'Thank them, hear them out fully, dig in, and change it if they’re right', v: 2 },
    { t: 'Hear them now, then take it offline to look into it properly', v: 1 },
    { t: 'Calmly explain the reasoning behind the policy', v: 0 },
    { t: 'Thank them and tell them you’ll note it for review', v: 0 } ] },
  { c: 'vision', s: 'The team is hitting every number, but the work has quietly gone transactional and a little cold.', o: [
    { t: 'Re-anchor everyone on the purpose and raise the standard of care', v: 2 },
    { t: 'Start telling client-impact stories in every huddle', v: 1 },
    { t: 'Add recognition for warmth, not just output', v: 1 },
    { t: 'Leave it — the numbers say it’s working', v: 0 } ] },
  { c: 'decisiveness', s: 'You have about 70% of the information and the decision is already overdue.', o: [
    { t: 'Decide now, communicate clearly, and adjust as you learn', v: 2 },
    { t: 'Make a reversible first move and keep gathering information', v: 1 },
    { t: 'Bring the team in to build consensus before committing', v: 1 },
    { t: 'Wait for more certainty so you don’t decide wrong', v: 0 } ] },
];
function empLead(uid) { try { const r = db.prepare(`SELECT leadership FROM employee_profiles WHERE user_id=?`).get(uid); return r && r.leadership ? JSON.parse(r.leadership) : null; } catch { return null; } }
function saveLead(uid, lead) {
  const ex = db.prepare(`SELECT user_id FROM employee_profiles WHERE user_id=?`).get(uid);
  if (ex) db.prepare(`UPDATE employee_profiles SET leadership=? WHERE user_id=?`).run(JSON.stringify(lead), uid);
  else db.prepare(`INSERT INTO employee_profiles (user_id, leadership) VALUES (?,?)`).run(uid, JSON.stringify(lead));
}
const LEADER_ROLES = ['Executive Director', 'Director of Operations', 'Clinical Director', 'Housing Director', 'HR'];
const isLeader = (u) => u.role === 'admin' || LEADER_ROLES.includes(u.job_role || '');
// Real org signals a top consultant would put in front of a leader — pulled live.
function leadershipSignals() {
  const staff = db.prepare(`SELECT id, name, job_role FROM users WHERE active=1 AND role!='admin'`).all();
  const cur = [], prev = [];
  staff.forEach((u) => { const s = userStats(u); if (s.overall != null) cur.push(s.overall); const p = prevOverall(u); if (p != null) prev.push(p); });
  const avg = (a) => a.length ? Math.round(a.reduce((x, y) => x + y, 0) / a.length) : null;
  const teamAvg = avg(cur), teamPrev = avg(prev);
  return { teamAvg, teamTrend: (teamAvg != null && teamPrev != null) ? teamAvg - teamPrev : null, teamN: cur.length };
}
function leaderOwnSignals(u) {
  const recognitionGiven = db.prepare(`SELECT COUNT(*) n FROM wows WHERE by_id=? AND created_at>=datetime('now','-30 day')`).get(u.id).n;
  const coachingNotes = db.prepare(`SELECT COUNT(*) n FROM employee_notes WHERE by_name=? AND created_at>=datetime('now','-30 day')`).get(u.name).n;
  return { recognitionGiven, coachingNotes };
}
// Permission: you can see your OWN mirror if you lead; admin (CEO) can see anyone's.
function canSeeMirror(user, targetId) { return user.role === 'admin' || (isLeader(user) && user.id === targetId); }
app.get('/api/leadership/mirror/:id', requireAuth, (req, res) => {
  const id = +req.params.id;
  if (!canSeeMirror(req.user, id)) return res.status(403).json({ error: 'Leadership only.' });
  const u = db.prepare(`SELECT id, name, job_role, role FROM users WHERE id=?`).get(id);
  if (!u) return res.status(404).json({ error: 'Not found' });
  if (!isLeader(u)) return res.status(400).json({ error: 'Not a leadership role.' });
  const lead = empLead(id);
  res.json({
    user: { id: u.id, name: u.name, role: u.role === 'admin' ? 'Owner / CEO' : (u.job_role || 'Leader') },
    lead, comps: LEAD_COMPS, styleBlocks: LEAD_FC, judgmentQuestions: LEAD_SJT,
    org: leadershipSignals(), own: leaderOwnSignals(u), aiReady: claudeConfigured(),
  });
});
// CEO + each leader: the roster of leaders the CEO can mirror.
app.get('/api/leadership/leaders', requireAuth, (req, res) => {
  if (req.user.role !== 'admin') return res.status(403).json({ error: 'Owner only.' });
  const rows = db.prepare(`SELECT id, name, job_role, role FROM users WHERE active=1 AND (role='admin' OR job_role IN ('Executive Director','Director of Operations','Clinical Director','Housing Director','HR')) ORDER BY role='admin' DESC, name`).all();
  const leaders = rows.map((u) => { const l = empLead(u.id); return { id: u.id, name: u.name, role: u.role === 'admin' ? 'Owner / CEO' : (u.job_role || 'Leader'), taken: !!(l && l.style && l.judgment) }; });
  res.json({ leaders });
});
app.post('/api/leadership/mirror/:id/style', requireAuth, (req, res) => {
  const id = +req.params.id;
  if (!canSeeMirror(req.user, id)) return res.status(403).json({ error: 'Leadership only.' });
  const ans = req.body?.answers || {}; const score = {}, seen = {};
  Object.keys(LEAD_COMPS).forEach((k) => { score[k] = 0; seen[k] = 0; });
  let answered = 0;
  LEAD_FC.forEach((block, i) => {
    const a = ans[i]; if (!a || a.most == null || a.least == null || a.most === a.least) return;
    const most = block[+a.most], least = block[+a.least]; if (!most || !least) return;
    answered++; block.forEach((o) => { seen[o.k]++; }); score[most.k] += 1; score[least.k] -= 1;
  });
  if (answered < LEAD_FC.length) return res.status(400).json({ error: 'Pick a Most and a Least in every block.' });
  const style = { at: new Date().toISOString().slice(0, 10) };
  Object.keys(LEAD_COMPS).forEach((k) => { style[k] = seen[k] ? Math.max(0, Math.min(100, Math.round(50 + (score[k] / seen[k]) * 50))) : 50; });
  const lead = empLead(id) || {}; lead.style = style; saveLead(id, lead);
  res.json({ ok: true, style });
});
app.post('/api/leadership/mirror/:id/judgment', requireAuth, (req, res) => {
  const id = +req.params.id;
  if (!canSeeMirror(req.user, id)) return res.status(403).json({ error: 'Leadership only.' });
  const ans = req.body?.answers || {}; const earned = {}, max = {};
  Object.keys(LEAD_COMPS).forEach((c) => { earned[c] = 0; max[c] = 0; });
  let answered = 0;
  LEAD_SJT.forEach((q, i) => { max[q.c] += 2; const p = ans[i]; if (p == null || !q.o[+p]) return; answered++; earned[q.c] += q.o[+p].v; });
  if (answered < LEAD_SJT.length) return res.status(400).json({ error: 'Answer every scenario.' });
  const judgment = { at: new Date().toISOString().slice(0, 10) };
  Object.keys(LEAD_COMPS).forEach((c) => { judgment[c] = max[c] ? Math.round(earned[c] / max[c] * 100) : null; });
  const lead = empLead(id) || {}; lead.judgment = judgment; saveLead(id, lead);
  res.json({ ok: true, judgment });
});
app.post('/api/leadership/mirror/:id/coach', requireAuth, async (req, res) => {
  const id = +req.params.id;
  if (!canSeeMirror(req.user, id)) return res.status(403).json({ error: 'Leadership only.' });
  if (!claudeConfigured()) return res.status(503).json({ error: 'AI is not configured.' });
  const u = db.prepare(`SELECT id, name, job_role, role FROM users WHERE id=?`).get(id);
  if (!u) return res.status(404).json({ error: 'Not found' });
  const lead = empLead(id) || {}; const org = leadershipSignals(); const own = leaderOwnSignals(u);
  const self = req.user.id === id;
  const fmt = (o) => o ? Object.keys(LEAD_COMPS).map((k) => `${LEAD_COMPS[k]} ${o[k]}`).join(', ') : 'not taken yet';
  const ctx = [
    `Leader: ${u.name} — ${u.role === 'admin' ? 'Owner / CEO' : (u.job_role || 'leader')}`,
    `Leadership STYLE (forced-choice, 0-100, can't be gamed): ${fmt(lead.style)}`,
    `Leadership JUDGMENT (real dilemmas, 0-100): ${fmt(lead.judgment)}`,
    `REAL ORG DATA they help lead: team performance avg ${org.teamAvg != null ? org.teamAvg + '%' : 'n/a'} across ${org.teamN} staff, trend ${org.teamTrend != null ? (org.teamTrend >= 0 ? '+' : '') + org.teamTrend : 'n/a'} vs prior period.`,
    `Their own leadership behavior (30d): recognition given to staff = ${own.recognitionGiven}; coaching notes logged = ${own.coachingNotes}.`,
  ].filter(Boolean).join('\n');
  const q = `You are Horst Schulze, Ritz-Carlton co-founder, acting as the highest-level executive coach. You are giving ${self ? 'this leader, directly,' : 'the CEO, about one of their leaders,'} an HONEST read — the kind a great consultant gives behind closed doors. We lead the way we ask our people to serve: dignity, genuine care, uncompromising standards. Use ONLY the data provided; don't invent specifics. Be direct and warm — name the hard things kindly but clearly. Give five short labeled parts:\n1) WHERE YOU STRIVE — the real strengths (tie to the data).\n2) WHERE YOU STRUGGLE — the honest growth edges, named plainly (never cruel).\n3) THE BLIND SPOT — the one thing they likely can't see in themselves.\n4) HOW YOU LEAD BEST — the conditions and approach where this person is at their best.\n5) ONE MOVE THIS WEEK — a single concrete action to grow.\n${self ? 'Address them as "you".' : 'Refer to the leader by name.'}`;
  try { const brief = await askAssistant(q, ctx); res.json({ brief }); }
  catch (e) { res.status(502).json({ error: e.message }); }
});

/* ───────────── GROWTH PLAN — every employee's own goals & monthly check-in ─────────────
   This is THEIRS. Where do you want to be in 6 months, a year, 5 years, 10 years —
   and every month, how are you tracking and how can we help you get closer? The
   employee owns their goals and can see everything; leadership can support and log
   check-ins from the employee profile. Growth, not surveillance. */
function growthPlan(uid) { return db.prepare(`SELECT goal_6m, goal_1y, goal_5y, goal_10y, why, updated, updated_by FROM growth_plans WHERE user_id=?`).get(uid) || {}; }
function growthCheckins(uid) { return db.prepare(`SELECT id, progress, support, by_name, self, substr(created_at,1,10) at FROM growth_checkins WHERE user_id=? ORDER BY id DESC LIMIT 36`).all(uid); }
function growthHasGoals(p) { return !!(p && (p.goal_6m || p.goal_1y || p.goal_5y || p.goal_10y)); }
function checkinDue(uid) {
  const p = growthPlan(uid); if (!growthHasGoals(p)) return false;
  const last = db.prepare(`SELECT created_at FROM growth_checkins WHERE user_id=? ORDER BY id DESC LIMIT 1`).get(uid);
  if (!last) return true;
  const r = db.prepare(`SELECT (julianday('now') - julianday(?)) d`).get(last.created_at);
  return r && r.d >= 28;   // monthly cadence
}
function saveGrowthGoals(uid, b, byName) {
  const v = ['goal_6m', 'goal_1y', 'goal_5y', 'goal_10y', 'why'].map((f) => (b[f] || '').trim().slice(0, 800) || null);
  const ex = db.prepare(`SELECT user_id FROM growth_plans WHERE user_id=?`).get(uid);
  if (ex) db.prepare(`UPDATE growth_plans SET goal_6m=?,goal_1y=?,goal_5y=?,goal_10y=?,why=?,updated=datetime('now'),updated_by=? WHERE user_id=?`).run(...v, byName, uid);
  else db.prepare(`INSERT INTO growth_plans (user_id,goal_6m,goal_1y,goal_5y,goal_10y,why,updated,updated_by) VALUES (?,?,?,?,?,?,datetime('now'),?)`).run(uid, ...v, byName);
}
function addGrowthCheckin(uid, b, byName, isSelf) {
  const progress = (b.progress || '').trim().slice(0, 1500), support = (b.support || '').trim().slice(0, 1500);
  if (!progress && !support) return false;
  db.prepare(`INSERT INTO growth_checkins (user_id, progress, support, by_name, self) VALUES (?,?,?,?,?)`).run(uid, progress || null, support || null, byName, isSelf ? 1 : 0);
  return true;
}
// Every employee: their own growth plan.
app.get('/api/growth/me', requireAuth, (req, res) => {
  res.json({ plan: growthPlan(req.user.id), checkins: growthCheckins(req.user.id), due: checkinDue(req.user.id), self: true });
});
app.post('/api/growth/me', requireAuth, (req, res) => { saveGrowthGoals(req.user.id, req.body || {}, req.user.name); res.json({ ok: true }); });
app.post('/api/growth/me/checkin', requireAuth, (req, res) => {
  if (!addGrowthCheckin(req.user.id, req.body || {}, req.user.name, true)) return res.status(400).json({ error: 'Add your progress or what would help.' });
  res.json({ ok: true });
});
// Leadership: support an employee's growth from their profile.
app.get('/api/growth/:id', requireAuth, (req, res) => {
  if (!canSeeTeamStats(req.user)) return res.status(403).json({ error: 'Leadership only.' });
  const uid = +req.params.id;
  res.json({ plan: growthPlan(uid), checkins: growthCheckins(uid), due: checkinDue(uid), self: false });
});
app.post('/api/growth/:id/checkin', requireAuth, (req, res) => {
  if (!canSeeTeamStats(req.user)) return res.status(403).json({ error: 'Leadership only.' });
  if (!addGrowthCheckin(+req.params.id, req.body || {}, req.user.name, false)) return res.status(400).json({ error: 'Add a note.' });
  res.json({ ok: true });
});
