// Outcomes + milestones
app.get('/api/outcomes', requireAuth, (req, res) => {
  const disc = db.prepare(`SELECT discharge_status s, COUNT(*) n FROM clients WHERE discharge_status IS NOT NULL GROUP BY discharge_status`).all();
  const counts = {}; disc.forEach((r) => { counts[r.s] = r.n; });
  const completed = counts.Completed || 0, ama = counts.AMA || 0, transferred = counts.Transferred || 0;
  const denom = completed + ama;
  const amaRate = denom ? Math.round((ama / denom) * 100) : 0;
  const completionRate = denom ? Math.round((completed / denom) * 100) : 0;
  const active = db.prepare(`SELECT COUNT(*) n FROM clients WHERE active = 1 AND discharge_status IS NULL`).get().n;
  const since = new Date(Date.now() - 30 * 864e5).toISOString().slice(0, 10);
  const ce = db.prepare(`SELECT AVG(cared) a, COUNT(*) n FROM client_experience WHERE date >= ?`).get(since);
  const openConcerns = db.prepare(`SELECT COUNT(*) n FROM concerns WHERE status = 'Open'`).get().n;
  const delights30 = db.prepare(`SELECT COUNT(*) n FROM delights WHERE created_at >= datetime('now','-30 day')`).get().n;

  const clients = db.prepare(`SELECT pref, name, sober FROM clients WHERE active = 1 AND discharge_status IS NULL AND sober IS NOT NULL AND sober != ''`).all();
  const now = Date.now();
  const milestones = [];
  clients.forEach((c) => {
    [7, 30, 60, 90].forEach((d) => {
      const ms = new Date(c.sober + 'T00:00').getTime() + d * 864e5;
      const inDays = Math.round((ms - now) / 864e5);
      if (inDays >= 0 && inDays <= 7) milestones.push({ client: c.pref || c.name, label: `${d} days sober`, date: new Date(ms).toISOString().slice(0, 10), inDays });
    });
  });
  milestones.sort((a, b) => a.inDays - b.inDays);

  res.json({ amaRate, completionRate, completed, ama, transferred, active,
    feltCare: ce.a ? Math.round(ce.a * 10) / 10 : null, feltCareN: ce.n,
    openConcerns, delights30, milestones, surveys: surveyMetrics(30) });
});

/* ---------------- Departments, Concierge, Program, Goals, Journey, AI briefs ---------------- */

// Concierge requests
app.get('/api/requests', requireAuth, (req, res) => {
  const fc = facCtx(req); if (denyFac(fc, res)) return;
  let sql = `SELECT r.*, c.pref, c.name FROM requests r LEFT JOIN clients c ON c.id = r.client_id WHERE 1=1${fc.frag('r.facility_id')}`;
  const args = [];
  if (req.query.status) { sql += ` AND r.status = ?`; args.push(req.query.status); }
  if (req.query.department) { sql += ` AND r.department = ?`; args.push(req.query.department); }
  sql += ` ORDER BY (r.status = 'Done'), (r.priority = 'High') DESC, r.id DESC LIMIT 200`;
  res.json({ requests: db.prepare(sql).all(...args) });
});
app.get('/api/requests/count', requireAuth, (req, res) => { const fc = facCtx(req); if (denyFac(fc, res)) return; res.json({ open: db.prepare(`SELECT COUNT(*) n FROM requests WHERE status != 'Done'${fc.frag('facility_id')}`).get().n }); });
// Concierge performance: team averages + a fastest-responder leaderboard.
app.get('/api/requests/stats', requireAuth, (req, res) => {
  const days = Math.min(90, Math.max(1, +(req.query.days || 7)));
  const since = `-${days} day`;
  const respMin = `(julianday(acknowledged_at) - julianday(created_at)) * 1440`;
  const team = db.prepare(`SELECT
      COUNT(*) total,
      SUM(CASE WHEN status='Done' THEN 1 ELSE 0 END) done,
      SUM(CASE WHEN status!='Done' THEN 1 ELSE 0 END) open,
      AVG(CASE WHEN acknowledged_at IS NOT NULL THEN ${respMin} END) avgResp,
      AVG(CASE WHEN done_at IS NOT NULL THEN (julianday(done_at)-julianday(created_at))*1440 END) avgResolve,
      SUM(CASE WHEN acknowledged_at IS NOT NULL THEN 1 ELSE 0 END) respondedN,
      SUM(CASE WHEN acknowledged_at IS NOT NULL AND ${respMin} <= 15 THEN 1 ELSE 0 END) within15
    FROM requests WHERE created_at >= datetime('now', ?)${facCtx(req).frag('facility_id')}`).get(since);
  const board = db.prepare(`SELECT acknowledged_by name, COUNT(*) n, AVG(${respMin}) avgResp
    FROM requests WHERE acknowledged_at IS NOT NULL AND acknowledged_by IS NOT NULL AND acknowledged_by != ''
      AND created_at >= datetime('now', ?)${facCtx(req).frag('facility_id')}
    GROUP BY acknowledged_by HAVING n >= 1 ORDER BY avgResp ASC LIMIT 10`).all(since);
  const r1 = (x) => x == null ? null : Math.round(x);
  res.json({
    days,
    total: team.total || 0, done: team.done || 0, open: team.open || 0,
    avgRespMin: r1(team.avgResp), avgResolveMin: r1(team.avgResolve),
    within15Pct: team.respondedN ? Math.round(team.within15 / team.respondedN * 100) : null,
    leaderboard: board.map((b) => ({ name: b.name, n: b.n, avgRespMin: r1(b.avgResp) })),
  });
});
function conciergeEmailTo() { return (getState('concierge_email') || getState('census_email_to') || process.env.CENSUS_EMAIL_TO || '').trim(); }
// Every request (staff- or kiosk-logged) raises its own alert + emails concierge.
// Unique kind per request id so repeats are never deduped away. `by` is who logged it.
async function announceRequest(id, { client_id, department, text, priority, by }) {
  const hi = priority === 'High' || priority === 'Urgent';
  const c = client_id ? db.prepare(`SELECT pref, name, room FROM clients WHERE id = ?`).get(client_id) : null;
  const who = c ? `${c.pref || (c.name || '').split(/\s+/)[0] || 'a client'}${c.room ? ' · Room ' + c.room : ''}` : 'House';
  createAlert(client_id || null, 'request_' + id, hi ? 'High' : 'Elevated', `${hi ? 'Priority request' : 'Concierge request'} — ${department}: ${String(text).slice(0, 90)} (${who})`);
  const to = conciergeEmailTo();
  if (!to) return { emailed: false, reason: 'no concierge recipient set' };
  if (!emailConfigured()) return { emailed: false, reason: 'email not connected (Settings → Email)' };
  const subject = `${hi ? '🔴 Priority' : 'New'} concierge request — ${department}`;
  const html = `<div style="font-family:Georgia,serif"><h3>${hi ? '🔴 Priority ' : ''}Concierge request</h3>
    <p><b>${htmlEsc(department)}</b>${hi ? ' · <b style="color:#b00">Priority</b>' : ''}</p>
    <p style="font-size:15px">${htmlEsc(String(text))}</p>
    <p style="color:#555">For: ${htmlEsc(who)}${by ? ' · ' + htmlEsc(by) : ''}</p>
    <p style="color:#888;font-size:12px">Open Armada → Concierge to assign it and start the clock.</p></div>`;
  try { await sendEmail({ to, subject, html, suppressCc: true }); return { emailed: true, to }; }
  catch (e) { console.error('[concierge email]', e.message); return { emailed: false, to, reason: e.message }; }
}
app.post('/api/requests', requireAuth, async (req, res) => {
  const { client_id, department, text, priority } = req.body || {};
  if (!department || !text?.trim()) return res.status(400).json({ error: 'Missing department or text' });
  const hi = priority === 'High';
  // Facility: the client's if named (trigger would do this too), else the caller's
  // scope, else default — so a house request (no client) never lands NULL/invisible.
  const rFac = (client_id ? db.prepare(`SELECT facility_id FROM clients WHERE id=?`).get(+client_id)?.facility_id : null) || facCtx(req).one || defaultFacilityId();
  const info = db.prepare(`INSERT INTO requests (client_id, department, text, priority, created_by, created_by_name, facility_id) VALUES (?, ?, ?, ?, ?, ?, ?)`)
    .run(client_id || null, department, text.trim(), hi ? 'High' : 'Normal', req.user.id, req.user.name, rFac);
  const r = await announceRequest(info.lastInsertRowid, { client_id, department, text: text.trim(), priority: hi ? 'High' : 'Normal', by: 'logged by ' + req.user.name });
  audit({ user: req.user, action: 'REQUEST', entity: 'client', entity_id: client_id ? +client_id : null, detail: department, ip: req.ip });
  res.json({ ok: true, id: info.lastInsertRowid, emailed: r.emailed, to: r.to || null, emailReason: r.reason || null });
});
app.post('/api/requests/:id/assign', requireAuth, (req, res) => {
  const u = req.body?.user_id ? db.prepare(`SELECT id, name FROM users WHERE id = ?`).get(+req.body.user_id) : null;
  // Assigning is the first response — start the clock if it hasn't started.
  db.prepare(`UPDATE requests SET assigned_to = ?, assigned_name = ?,
      status = CASE WHEN status = 'Open' THEN 'In progress' ELSE status END,
      acknowledged_at = COALESCE(acknowledged_at, datetime('now')),
      acknowledged_by = COALESCE(acknowledged_by, ?) WHERE id = ?`)
    .run(u?.id || null, u?.name || null, u?.name || req.user.name, req.params.id);
  res.json({ ok: true });
});
app.post('/api/requests/:id/status', requireAuth, (req, res) => {
  const st = ['Open', 'In progress', 'Done'].includes(req.body?.status) ? req.body.status : 'Done';
  // First move off 'Open' records the time-to-response.
  db.prepare(`UPDATE requests SET status = ?,
      acknowledged_at = CASE WHEN ? != 'Open' THEN COALESCE(acknowledged_at, datetime('now')) ELSE acknowledged_at END,
      acknowledged_by = CASE WHEN ? != 'Open' THEN COALESCE(acknowledged_by, ?) ELSE acknowledged_by END,
      done_by = CASE WHEN ? = 'Done' THEN ? ELSE done_by END,
      done_at = CASE WHEN ? = 'Done' THEN datetime('now') ELSE done_at END WHERE id = ?`)
    .run(st, st, st, req.user.name, st, req.user.id, st, req.params.id);
  if (st === 'Done') db.prepare(`UPDATE alerts SET status = 'Resolved' WHERE kind = ? AND status = 'New'`).run('request_' + req.params.id);
  res.json({ ok: true });
});

