const excWeek = (dstr) => { // Monday of the given app-day — one reflection per person per week
  const d = new Date(dstr + 'T12:00:00');
  d.setDate(d.getDate() - ((d.getDay() + 6) % 7));
  return d.toISOString().slice(0, 10);
};
