// Keep the roster current automatically: re-sync the live Kipu census on a
// schedule (default every 6h) so admits/discharges flow in without a manual
// rebuild. Set KIPU_SYNC_HOURS=0 to disable. Optionally KIPU_AUTO_ASSESS=true
// runs the risk assessment after each sync.
if (kipuConfigured()) {
  const hrs = process.env.KIPU_SYNC_HOURS != null ? +process.env.KIPU_SYNC_HOURS : 6;
  if (hrs > 0) {
    const autoSync = async () => {
      try {
        const r = await kipuSyncRoster();
        console.log(`[kipu] auto-sync: ${r.activeNow} active (${r.created} new, ${r.deactivated} discharged)`);
        try { const n = autoMergeShellDuplicates(); if (n) console.log(`[auto-dedupe] merged ${n} shell duplicate(s)`); } catch (e) { console.error('[auto-dedupe]:', e.message); }
        try { ensureDignityKits(); } catch (e) { /* non-fatal */ }
        // Re-assess the census automatically (clears stale alerts + refreshes every
        // client's clean read/snapshot). Disable with KIPU_AUTO_ASSESS=false.
        if (claudeConfigured() && process.env.KIPU_AUTO_ASSESS !== 'false' && !assessJob.running) {
          await runAssessAll({ id: null, name: 'Auto-sync' }, { incremental: true });
        }
        // Anyone newly discharged gets an automatic "what could we do better" debrief.
        if (claudeConfigured() && !debriefJob.running) runDischargeDebriefs({ id: null, name: 'Auto-sync' }).catch((e) => { debriefJob.running = false; console.error('[debrief]', e.message); });
      } catch (e) { console.error('[kipu] auto-sync failed:', e.message); }
    };
    setTimeout(autoSync, 30000);                 // first run shortly after boot
    setInterval(autoSync, hrs * 3600 * 1000);    // then on the interval
  }
}
// Per-facility auto-sync (Phase 4): a facility whose own 🔌 connection has been
// verified by a hand-run sync can opt into the schedule (autoSync in its config).
// Runs whether or not the primary env connection exists; kipuSyncRoster's chain
// serializes everything, and each facility's failure is isolated to its log line.
{
  const hrs = process.env.KIPU_SYNC_HOURS != null ? +process.env.KIPU_SYNC_HOURS : 6;
  if (hrs > 0) {
    const facAutoSync = async () => {
      let rows = [];
      try { rows = db.prepare(`SELECT fi.facility_id, fi.config, f.name, f.type, f.kipu_location_name FROM facility_integrations fi JOIN org_facilities f ON f.id = fi.facility_id AND f.active = 1 WHERE fi.kind = 'kipu' AND fi.active = 1`).all(); } catch { return; }
      for (const row of rows) {
        try {
          let c = {}; try { c = JSON.parse(row.config || '{}'); } catch { continue; }
          if (!c.autoSync) continue;
          if (!(c.accessId && c.secretKey && c.appId)) continue;
          // Outpatient facilities sync the PHP/IOP/OP roster; bedded ones the census.
          if (row.type === 'outpatient') {
            const r = await syncOutpatient({ facilityId: row.facility_id, locationName: row.kipu_location_name || '', conn: c });
            if (r.error) console.error('[kipu] facility auto-sync (' + row.name + '):', r.error);
            else console.log(`[kipu] facility auto-sync ${row.name}: ${r.counts?.total ?? '?'} enrolled (outpatient)`);
          } else {
            const r = await kipuSyncRoster({ conn: c, facilityId: row.facility_id, locationId: c.locationId || '', locationName: row.kipu_location_name || '' });
            console.log(`[kipu] facility auto-sync ${row.name}: ${r.activeNow} active (${r.created} new, ${r.deactivated} discharged)`);
          }
        } catch (e) { console.error('[kipu] facility auto-sync (' + row.name + '):', e.message); }
      }
    };
    setTimeout(facAutoSync, 90000);              // after the primary's first pass
    setInterval(facAutoSync, hrs * 3600 * 1000);
  }
}
